// FamilyMemberDetails.tsx
import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  UserIcon,
  PencilIcon,
  ArrowPathIcon,
  ChartBarIcon,
  ClockIcon,
} from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import ProgressBar from '../../components/common/ProgressBar';
import TransactionItem from '../../components/banking/TransactionItem';
import LimitSetter from '../../components/family/LimitSetter';
import { useFamily } from '../../hooks/useFamily';
import { useWallet } from '../../hooks/useWallet';

const FamilyMemberDetails: React.FC = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { getMemberDetails, updateLimits, addToLimit, pauseMember, resumeMember } = useFamily();
  const { getMemberTransactions } = useWallet();
  const [member, setMember] = useState<any>(null);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [showEditLimits, setShowEditLimits] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, [id]);

  const loadData = async () => {
    setLoading(true);
    const memberData = await getMemberDetails(id!);
    const txnData = await getMemberTransactions(id!);
    setMember(memberData);
    setTransactions(txnData);
    setLoading(false);
  };

  const handleAddLimit = async () => {
    const amount = prompt('Enter amount to add to daily limit:');
    if (amount) {
      await addToLimit(id!, parseFloat(amount));
      loadData();
    }
  };

  const handlePause = async () => {
    if (confirm('Pause this member?')) {
      await pauseMember(id!);
      loadData();
    }
  };

  const handleResume = async () => {
    await resumeMember(id!);
    loadData();
  };

  if (loading) return <div className="text-center py-8">Loading...</div>;

  const dailyPercent = (member.dailySpent / member.dailyLimit) * 100;
  const monthlyPercent = (member.monthlySpent / member.monthlyLimit) * 100;

  return (
    <div>
      {/* Header */}
      <div className="flex justify-between items-start mb-6">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-primary-soft rounded-full flex items-center justify-center">
            <UserIcon className="h-8 w-8 text-primary" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">{member.name}</h1>
            <p className="text-gray-600">{member.phone}</p>
            <p className="text-sm text-gray-500">{member.relationship}</p>
          </div>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => setShowEditLimits(true)}>
            <PencilIcon className="h-4 w-4 mr-1" /> Edit Limits
          </Button>
          {member.status === 'ACTIVE' ? (
            <Button variant="outline" size="sm" onClick={handlePause}>
              Pause
            </Button>
          ) : (
            <Button variant="outline" size="sm" onClick={handleResume}>
              Resume
            </Button>
          )}
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
        <Card>
          <div className="flex items-center gap-2 mb-2">
            <ChartBarIcon className="h-5 w-5 text-primary" />
            <h3 className="font-semibold">Daily Usage</h3>
          </div>
          <p className="text-2xl font-bold mb-2">
            ₹{member.dailySpent} / ₹{member.dailyLimit}
          </p>
          <ProgressBar value={dailyPercent} color={dailyPercent > 80 ? 'warning' : 'primary'} />
          <p className="text-sm text-gray-500 mt-2">Resets at midnight</p>
        </Card>

        <Card>
          <div className="flex items-center gap-2 mb-2">
            <ChartBarIcon className="h-5 w-5 text-success" />
            <h3 className="font-semibold">Monthly Usage</h3>
          </div>
          <p className="text-2xl font-bold mb-2">
            ₹{member.monthlySpent} / ₹{member.monthlyLimit}
          </p>
          <ProgressBar value={monthlyPercent} color={monthlyPercent > 80 ? 'warning' : 'success'} />
          <p className="text-sm text-gray-500 mt-2">Resets on 1st</p>
        </Card>

        <Card>
          <div className="flex items-center gap-2 mb-2">
            <ClockIcon className="h-5 w-5 text-warning" />
            <h3 className="font-semibold">Quick Actions</h3>
          </div>
          <Button variant="primary" size="sm" fullWidth onClick={handleAddLimit} className="mb-2">
            Add to Limit
          </Button>
          <Button
            variant="outline"
            size="sm"
            fullWidth
            onClick={() => navigate(`/primary/send?to=${member.id}`)}
          >
            Send Money
          </Button>
        </Card>
      </div>

      {/* Permissions */}
      <Card className="mb-6">
        <h3 className="font-semibold mb-3">Permissions</h3>
        <div className="grid grid-cols-2 gap-2">
          {Object.entries(member.permissions).map(([key, value]) => (
            <div key={key} className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${value ? 'bg-success' : 'bg-gray-300'}`} />
              <span className="text-sm text-gray-700 capitalize">
                {key.replace(/([A-Z])/g, ' $1').trim()}
              </span>
            </div>
          ))}
        </div>
      </Card>

      {/* Recent Transactions */}
      <Card>
        <div className="flex justify-between items-center mb-4">
          <h3 className="font-semibold">Recent Transactions</h3>
          <Button
            variant="outline"
            size="sm"
            onClick={() => navigate(`/primary/transactions?member=${id}`)}
          >
            View All
          </Button>
        </div>
        {transactions.map((txn) => (
          <TransactionItem key={txn.id} transaction={txn} />
        ))}
      </Card>

      {/* Edit Limits Modal */}
      {showEditLimits && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="max-w-md w-full">
            <LimitSetter
              memberName={member.name}
              initialValues={{
                dailyLimit: member.dailyLimit,
                monthlyLimit: member.monthlyLimit,
                perTransactionLimit: member.perTransactionLimit,
                ...member.permissions,
              }}
              onSubmit={async (data) => {
                await updateLimits(id!, data);
                setShowEditLimits(false);
                loadData();
              }}
              onCancel={() => setShowEditLimits(false)}
            />
          </div>
        </div>
      )}
    </div>
  );
};

export default FamilyMemberDetails;
