// TransactionItem.tsx
import React from 'react';
import {
  ArrowUpIcon,
  ArrowDownIcon,
  ArrowPathIcon,
  BanknotesIcon,
  QrCodeIcon,
} from '@heroicons/react/24/outline';

interface TransactionItemProps {
  transaction: {
    id: string;
    transactionId: string;
    amount: number;
    type:
      | 'SEND'
      | 'RECEIVE'
      | 'RECHARGE'
      | 'ADD_TO_WALLET'
      | 'ADD_TO_LIMIT'
      | 'WITHDRAW'
      | 'PAYMENT';
    status: 'PENDING' | 'SUCCESS' | 'FAILED' | 'REFUNDED';
    description?: string | null;
    createdAt: string;
    senderName?: string;
    receiverName?: string;
    bankName?: string;
    metadata?: any;
  };
  onClick?: () => void;
}

const TransactionItem: React.FC<TransactionItemProps> = ({ transaction, onClick }) => {
  const getIcon = () => {
    switch (transaction.type) {
      case 'SEND':
        return <ArrowUpIcon className="h-5 w-5 text-error" />;
      case 'RECEIVE':
        return <ArrowDownIcon className="h-5 w-5 text-success" />;
      case 'RECHARGE':
        return <ArrowPathIcon className="h-5 w-5 text-primary" />;
      case 'ADD_TO_WALLET':
        return <BanknotesIcon className="h-5 w-5 text-primary" />;
      case 'PAYMENT':
        return <QrCodeIcon className="h-5 w-5 text-primary" />;
      default:
        return <BanknotesIcon className="h-5 w-5 text-gray-500" />;
    }
  };

  const getStatusColor = () => {
    switch (transaction.status) {
      case 'SUCCESS':
        return 'text-success bg-green-50';
      case 'PENDING':
        return 'text-warning bg-yellow-50';
      case 'FAILED':
        return 'text-error bg-red-50';
      case 'REFUNDED':
        return 'text-gray-600 bg-gray-50';
      default:
        return 'text-gray-600 bg-gray-50';
    }
  };

  const getTitle = () => {
    if (transaction.description) return transaction.description;

    switch (transaction.type) {
      case 'SEND':
        return `To ${transaction.receiverName || 'Unknown'}`;
      case 'RECEIVE':
        return `From ${transaction.senderName || 'Unknown'}`;
      case 'RECHARGE':
        return transaction.metadata?.mobileNumber
          ? `Recharge for ${transaction.metadata.mobileNumber}`
          : 'Mobile Recharge';
      case 'ADD_TO_WALLET':
        return 'Added to Wallet';
      case 'ADD_TO_LIMIT':
        return `Added to ${transaction.metadata?.memberName || 'Family'} limit`;
      case 'PAYMENT':
        return `Payment to ${transaction.metadata?.merchantName || 'Merchant'}`;
      default:
        return 'Transaction';
    }
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diff = now.getTime() - date.getTime();
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (days === 0) return 'Today';
    if (days === 1) return 'Yesterday';
    if (days < 7) return `${days} days ago`;
    return date.toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
  };

  const formatTime = (dateString: string) => {
    return new Date(dateString).toLocaleTimeString('en-IN', {
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  return (
    <div
      onClick={onClick}
      className="flex items-center gap-4 p-4 bg-white hover:bg-gray-50 rounded-lg cursor-pointer transition-colors border border-gray-100 mb-2"
    >
      <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center">
        {getIcon()}
      </div>

      <div className="flex-1">
        <div className="flex justify-between items-start">
          <div>
            <h4 className="font-medium text-gray-900">{getTitle()}</h4>
            <p className="text-xs text-gray-500 mt-1">
              {formatDate(transaction.createdAt)} at {formatTime(transaction.createdAt)}
            </p>
          </div>
          <span className={`text-xs px-2 py-1 rounded-full ${getStatusColor()}`}>
            {transaction.status}
          </span>
        </div>

        <div className="flex justify-between items-center mt-2">
          <span className="text-xs text-gray-500">{transaction.transactionId.slice(0, 12)}...</span>
          <span
            className={`font-bold ${transaction.type === 'SEND' ? 'text-error' : 'text-success'}`}
          >
            {transaction.type === 'SEND' || transaction.type === 'PAYMENT' ? '-' : '+'}₹
            {transaction.amount.toLocaleString()}
          </span>
        </div>

        {transaction.bankName && (
          <p className="text-xs text-gray-400 mt-1">via {transaction.bankName}</p>
        )}
      </div>
    </div>
  );
};

export default TransactionItem;
