import React, { useEffect, useState, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { CheckCircleIcon, XCircleIcon } from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import toast from 'react-hot-toast';

const AcceptInvite: React.FC = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [verifying, setVerifying] = useState(true);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');

  const token = searchParams.get('token');
  const code = searchParams.get('code');
  const verificationDone = useRef(false);

  useEffect(() => {
    if (verificationDone.current) return;
    verificationDone.current = true;
    
    const verifyInvite = async () => {
      try {
        // In production, call your API to verify the invite
        await new Promise(resolve => setTimeout(resolve, 1500));
        
        if (token || code) {
          setSuccess(true);
          toast.success('Invite verified successfully!');
        } else {
          setError('Invalid invite link');
        }
      } catch (err) {
        setError('Failed to verify invite');
      } finally {
        setVerifying(false);
      }
    };

    verifyInvite();
  }, [token, code]);

  const handleCreateAccount = () => {
    // Navigate to signup with the invite token
    // User will create their OWN account with their phone
    navigate(`/auth?type=linked&invite=${token || code}`);
  };

  if (verifying) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <Card className="max-w-md w-full text-center py-12">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto mb-4"></div>
          <h2 className="text-xl font-semibold mb-2">Verifying Your Invite</h2>
          <p className="text-gray-600">Please wait while we verify your invite...</p>
        </Card>
      </div>
    );
  }

  if (success) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <Card className="max-w-md w-full text-center">
          <CheckCircleIcon className="h-16 w-16 text-success mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Invite Accepted!</h2>
          <p className="text-gray-600 mb-6">
            You've been invited to join a family account. Create your account with your own mobile number to get started.
          </p>
          
          <Button onClick={handleCreateAccount} fullWidth>
            Create Your Account
          </Button>
          
          <button
            onClick={() => navigate('/')}
            className="text-gray-500 hover:text-gray-700 text-sm mt-4"
          >
            Go Home
          </button>
        </Card>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <Card className="max-w-md w-full text-center">
          <XCircleIcon className="h-16 w-16 text-error mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Invite Failed</h2>
          <p className="text-gray-600 mb-6">{error}</p>
          <Button onClick={() => navigate('/join-family')} fullWidth>
            Try Again
          </Button>
        </Card>
      </div>
    );
  }

  return null;
};

export default AcceptInvite;