// PrimaryDashboard.tsx
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  WalletIcon,
  UsersIcon,
  ArrowTrendingUpIcon,
  BanknotesIcon,
  PlusIcon,
} from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
// import ProgressBar from '../../components/common/ProgressBar';
import TransactionItem from '../../components/banking/TransactionItem';
import FamilyMemberCard from '../../components/family/FamilyMemberCard';
import { useAuth } from '../../hooks/useAuth';
import { useWallet } from '../../hooks/useWallet';
import { useFamily } from '../../hooks/useFamily';

const PrimaryDashboard: React.FC = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const { balance, transactions, getTransactionStats } = useWallet();
  const { familyMembers, loading } = useFamily();
  const [stats, setStats] = useState({ today: 0, week: 0, month: 0 });

  useEffect(() => {
    loadStats();
  }, []);

const loadStats = async () => {
  const data = await getTransactionStats();
  setStats(data);
};



  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold text-gray-900">Welcome, {user?.name || 'User'}</h1>
        <Button onClick={() => navigate('/primary/send')}>Send Money</Button>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card className="bg-primary text-white">
          <WalletIcon className="h-8 w-8 mb-2" />
          <p className="text-sm opacity-90">Wallet Balance</p>
          <p className="text-2xl font-bold">₹{balance?.toLocaleString()}</p>
        </Card>
        <Card>
          <BanknotesIcon className="h-8 w-8 text-primary mb-2" />
          <p className="text-sm text-gray-600">Today's Spend</p>
          <p className="text-2xl font-bold">₹{stats.today}</p>
        </Card>
        <Card>
          <ArrowTrendingUpIcon className="h-8 w-8 text-primary mb-2" />
          <p className="text-sm text-gray-600">This Week</p>
          <p className="text-2xl font-bold">₹{stats.week}</p>
        </Card>
        <Card>
          <UsersIcon className="h-8 w-8 text-primary mb-2" />
          <p className="text-sm text-gray-600">Family Members</p>
          <p className="text-2xl font-bold">{familyMembers?.length || 0}</p>
        </Card>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-4 gap-3">
        {[
          { label: 'Add Money', icon: PlusIcon, path: '/wallet/add' },
          { label: 'Send', icon: WalletIcon, path: '/primary/send' },
          { label: 'Recharge', icon: ArrowTrendingUpIcon, path: '/primary/recharge' },
          { label: 'Family', icon: UsersIcon, path: '/primary/family' },
        ].map((action, i) => (
          <button
            key={i}
            onClick={() => navigate(action.path)}
            className="p-3 bg-white rounded-xl shadow-sm hover:shadow-md transition-shadow text-center"
          >
            <action.icon className="h-6 w-6 text-primary mx-auto mb-1" />
            <span className="text-xs text-gray-600">{action.label}</span>
          </button>
        ))}
      </div>

      {/* Family Section */}
      <div>
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-semibold">Family Members</h2>
          <Button variant="outline" size="sm" onClick={() => navigate('/primary/family/add')}>
            <PlusIcon className="h-4 w-4 mr-1" /> Add Member
          </Button>
        </div>
        <div className="grid md:grid-cols-2 gap-4">
          {familyMembers?.slice(0, 2).map((member) => (
            <FamilyMemberCard
              key={member.id}
              member={member}
              onView={(id) => navigate(`/primary/family/${id}`)}
              onAddLimit={(id) => navigate(`/primary/family/${id}/add-limit`)}
            />
          ))}
        </div>
      </div>

      {/* Recent Transactions */}
      <div>
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-semibold">Recent Transactions</h2>
          <Button variant="outline" size="sm" onClick={() => navigate('/primary/transactions')}>
            View All
          </Button>
        </div>
        <Card>
          {transactions?.slice(0, 5).map((txn) => (
            <TransactionItem key={txn.id} transaction={txn} />
          ))}
        </Card>
      </div>
    </div>
  );
};

export default PrimaryDashboard;
