// useAuth.ts
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { authAPI } from '../services/api/auth';
import { RootState, AppDispatch } from '../store';
import {
  setUser,
  setLoading,
  setError,
  setAuthenticated,
  logout as logoutAction,
} from '../store/slices/authSlice';

export const useAuth = () => {
  const dispatch = useDispatch<AppDispatch>();
  const navigate = useNavigate();
  const { user, isLoading, error, isAuthenticated } = useSelector((state: RootState) => state.auth);

  const sendOTP = async (phone: string) => {
    try {
      dispatch(setLoading(true));
      await authAPI.sendOTP({ phone });
      dispatch(setError(null));
    } catch (err: any) {
      dispatch(setError(err.response?.data?.message || 'Failed to send OTP'));
      throw err;
    } finally {
      dispatch(setLoading(false));
    }
  };

  const verifyOTP = async (
  phone: string,
  otp: string,
  userType?: 'primary' | 'linked',
) => {
  try {
    dispatch(setLoading(true));
    const response = await authAPI.verifyOTP({ phone, otp, userType });

    const data = response.data.data;

    // ✅ store only actual user
    dispatch(setUser(data.user));

    // ✅ store token separately
    if (data.token) {
      localStorage.setItem('token', data.token);
    }

    dispatch(setAuthenticated(true));

    return data;
  } catch (err: any) {
    dispatch(setError(err.response?.data?.message || 'Invalid OTP'));
    throw err;
  } finally {
    dispatch(setLoading(false));
  }
};


 const updateProfile = async (data: { name?: string; email?: string }) => {
  try {
    dispatch(setLoading(true));
    const response = await authAPI.updateProfile(data);

    if (user) {
      dispatch(setUser({ ...user, ...data }));
    }

    return response.data;
  } catch (err: any) {
    dispatch(setError(err.response?.data?.message || 'Update failed'));
    throw err;
  } finally {
    dispatch(setLoading(false));
  }
};


  const logout = async () => {
    try {
      await authAPI.logout();
      dispatch(logoutAction());
      navigate('/');
    } catch (err) {
      console.error('Logout error:', err);
    }
  };

  const getMe = async () => {
  const token = localStorage.getItem('token');

  if (!token) {
    dispatch(setUser(null));
    dispatch(setAuthenticated(false));
    return;
  }

  try {
    dispatch(setLoading(true));
    const response = await authAPI.getMe();

    const userData = response.data.data;

    dispatch(setUser(userData));
    dispatch(setAuthenticated(true));
  } catch (err) {
    localStorage.removeItem('token');
    dispatch(setUser(null));
    dispatch(setAuthenticated(false));
  } finally {
    dispatch(setLoading(false));
  }
};


  return {
    user,
    isLoading,
    error,
    isAuthenticated,
    sendOTP,
    verifyOTP,
    updateProfile,
    logout,
    getMe,
  };
};