// ReceiveMoney.tsx - CORRECT VERSION
import React, { useState } from 'react';
import { QRCodeSVG } from 'qrcode.react';
import { DocumentDuplicateIcon, ArrowDownTrayIcon } from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import Input from '../../components/common/Input';
import { useAuth } from '../../hooks/useAuth';

const ReceiveMoney: React.FC = () => {
  const { user } = useAuth();
  const [amount, setAmount] = useState('');
  const [showQR, setShowQR] = useState(false);

  const upiId = `${user?.phone}@snappay`;
  const qrData = JSON.stringify({
    pa: upiId,
    pn: user?.name || 'User',
    am: amount || undefined,
    cu: 'INR',
  });

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    toast.success('Copied to clipboard!');
  };

  return (
    <div className="max-w-2xl mx-auto">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Receive Money</h1>

      <div className="grid md:grid-cols-2 gap-6">
        {/* UPI ID Card */}
        <Card>
          <h2 className="text-lg font-semibold mb-4">Your UPI ID</h2>
          <div className="bg-gray-50 p-4 rounded-lg mb-4">
            <p className="text-sm text-gray-600 mb-1">Share this ID to receive money</p>
            <div className="flex items-center gap-2">
              <code className="flex-1 p-2 bg-white border rounded font-mono">{upiId}</code>
              <button
                onClick={() => copyToClipboard(upiId)}
                className="p-2 hover:bg-gray-100 rounded"
              >
                <DocumentDuplicateIcon className="h-5 w-5 text-gray-600" />
              </button>
            </div>
          </div>

          <div className="space-y-4">
            <Input
              label="Request Specific Amount (Optional)"
              type="number"
              placeholder="Enter amount"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
            />

            <Button variant="outline" fullWidth onClick={() => setShowQR(true)}>
              Generate QR with Amount
            </Button>
          </div>
        </Card>

        {/* QR Code Card */}
        <Card>
          <h2 className="text-lg font-semibold mb-4">Scan QR Code</h2>
          <div className="bg-white p-6 rounded-lg border-2 border-dashed flex flex-col items-center">
            <div className="bg-white p-4 rounded-lg shadow-sm mb-4">
              <QRCodeSVG value={qrData} size={200} />
            </div>

            <p className="text-sm text-gray-600 text-center mb-4">
              Ask sender to scan this QR code
              {amount && ` for ₹${amount}`}
            </p>

            <div className="flex gap-2">
              <button
                onClick={() => copyToClipboard(qrData)}
                className="p-2 hover:bg-gray-100 rounded"
              >
                <DocumentDuplicateIcon className="h-5 w-5" />
              </button>
              <button
                onClick={() => {
                  /* Download QR */
                }}
                className="p-2 hover:bg-gray-100 rounded"
              >
                <ArrowDownTrayIcon className="h-5 w-5" />
              </button>
            </div>
          </div>
        </Card>
      </div>

      {/* Request Money */}
      <Card className="mt-6">
        <h2 className="text-lg font-semibold mb-4">Request Money</h2>
        <div className="flex gap-3">
          <Input placeholder="Enter phone number or UPI ID" className="flex-1" />
          <Input placeholder="Amount" type="number" className="w-32" />
          <Button>Request</Button>
        </div>
      </Card>
    </div>
  );
};

export default ReceiveMoney;
