import React, { useEffect } from 'react';
import { useNavigate, useSearchParams, Link } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { PhoneIcon, QrCodeIcon } from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';
import Card from '../../components/common/Card';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { useAuth } from '../../hooks/useAuth';

const phoneSchema = z.object({
  phone: z.string().regex(/^[0-9]{10}$/, 'Enter valid 10-digit mobile number'),
});

type PhoneFormData = z.infer<typeof phoneSchema>;

const Login: React.FC = () => {
  const [searchParams] = useSearchParams();
  const userType = searchParams.get('type') || 'primary';
  const navigate = useNavigate();
  const { sendOTP, isLoading } = useAuth();

  // ✅ ADDED useEffect (Invite detection)
  useEffect(() => {
    const invite = searchParams.get('invite');
    if (invite) {
      toast.success('Please login with your phone number to complete the invite');
    }
  }, [searchParams]);

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<PhoneFormData>({
    resolver: zodResolver(phoneSchema),
  });

  const onSubmit = async (data: PhoneFormData) => {
    try {
      await sendOTP(data.phone);
      // Check if there's an invite parameter
      const invite = searchParams.get('invite');
      const inviteParam = invite ? `&invite=${invite}` : '';
      navigate(`/verify-otp?phone=${data.phone}&type=${userType}${inviteParam}`);
      toast.success('OTP sent! Check console for code');
    } catch (error: any) {
      toast.error(error.message || 'Failed to send OTP');
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
      <Card className="max-w-md w-full">
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            {userType === 'primary' ? 'Create Primary Account' : 'Join as Family Member'}
          </h1>
          <p className="text-gray-600">Enter mobile number to get started</p>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
          <Input
            label="Mobile Number"
            type="tel"
            placeholder="9876543210"
            icon={<PhoneIcon className="h-5 w-5" />}
            error={errors.phone?.message}
            {...register('phone')}
          />

          <Button type="submit" fullWidth size="lg" loading={isLoading}>
            Send OTP
          </Button>
        </form>

        {userType === 'linked' && (
          <div className="mt-8 pt-6 border-t border-gray-200">
            <p className="text-center text-gray-600 mb-4">
              Already have an invite from a family member?
            </p>
            
            <Link to="/join-family">
              <Button variant="outline" fullWidth size="md">
                <QrCodeIcon className="h-5 w-5 mr-2" />
                Connect via QR / Invite Code
              </Button>
            </Link>
            
            <p className="text-xs text-center text-gray-500 mt-4">
              Use QR code, SMS invite code, or manual entry to join an existing family
            </p>
          </div>
        )}

        {userType === 'primary' && (
          <div className="mt-6 text-center">
            <p className="text-gray-500 text-sm">Want to join an existing family instead?</p>
            <Link to="/join-family" className="text-primary hover:underline text-sm">
              Click here to connect as family member
            </Link>
          </div>
        )}

        <div className="mt-6 text-center text-sm text-gray-500">
          By proceeding, you agree to our{' '}
          <a href="/terms" className="text-primary hover:underline">
            Terms
          </a>{' '}
          and{' '}
          <a href="/privacy" className="text-primary hover:underline">
            Privacy Policy
          </a>
        </div>
      </Card>
    </div>
  );
};

export default Login;