// FamilyMemberCard.tsx
import React from 'react';
import { UserIcon, PauseIcon, PlayIcon } from '@heroicons/react/24/outline';
import Card from '../common/Card';
import Button from '../common/Button';
import ProgressBar from '../common/ProgressBar';

interface FamilyMemberCardProps {
  member: {
    id: string;
    name: string;
    phone: string;
    relationship?: string;
    dailyLimit: number;
    dailySpent: number;
    monthlyLimit: number;
    monthlySpent: number;
    status: 'ACTIVE' | 'PAUSED' | 'PENDING';
    lastActive?: string;
  };
  onView?: (id: string) => void;
  onEdit?: (id: string) => void;
  onPause?: (id: string) => void;
  onResume?: (id: string) => void;
  onAddLimit?: (id: string) => void;
}

const FamilyMemberCard: React.FC<FamilyMemberCardProps> = ({
  member,
  onView,
  onEdit,
  onPause,
  onResume,
  onAddLimit,
}) => {
  const dailyPercent = (member.dailySpent / member.dailyLimit) * 100;
  const monthlyPercent = (member.monthlySpent / member.monthlyLimit) * 100;

  const getStatusBadge = () => {
    switch (member.status) {
      case 'ACTIVE':
        return (
          <span className="px-2 py-1 bg-green-100 text-green-700 text-xs rounded-full">Active</span>
        );
      case 'PAUSED':
        return (
          <span className="px-2 py-1 bg-gray-100 text-gray-700 text-xs rounded-full">Paused</span>
        );
      case 'PENDING':
        return (
          <span className="px-2 py-1 bg-yellow-100 text-yellow-700 text-xs rounded-full">
            Pending
          </span>
        );
    }
  };

  return (
    <Card className={`${member.status === 'PAUSED' ? 'opacity-75' : ''}`}>
      <div className="flex items-start justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-primary-soft rounded-full flex items-center justify-center">
            <UserIcon className="h-6 w-6 text-primary" />
          </div>
          <div>
            <h3 className="font-semibold text-gray-900">{member.name}</h3>
            <p className="text-sm text-gray-600">{member.phone}</p>
            {member.relationship && <p className="text-xs text-gray-500">{member.relationship}</p>}
          </div>
        </div>
        {getStatusBadge()}
      </div>

      <div className="space-y-3 mb-4">
        <div>
          <div className="flex justify-between text-sm mb-1">
            <span className="text-gray-600">Daily Limit</span>
            <span className="font-medium">
              ₹{member.dailySpent} / ₹{member.dailyLimit}
            </span>
          </div>
          <ProgressBar
            value={dailyPercent}
            color={dailyPercent > 80 ? 'warning' : 'primary'}
            size="sm"
          />
        </div>

        <div>
          <div className="flex justify-between text-sm mb-1">
            <span className="text-gray-600">Monthly Limit</span>
            <span className="font-medium">
              ₹{member.monthlySpent} / ₹{member.monthlyLimit}
            </span>
          </div>
          <ProgressBar
            value={monthlyPercent}
            color={monthlyPercent > 80 ? 'warning' : 'primary'}
            size="sm"
          />
        </div>
      </div>

      {member.lastActive && (
        <p className="text-xs text-gray-400 mb-3">
          Last active: {new Date(member.lastActive).toLocaleDateString()}
        </p>
      )}

      <div className="flex flex-wrap gap-2 mt-2">
        {onView && (
          <Button variant="outline" size="sm" onClick={() => onView(member.id)}>
            View
          </Button>
        )}
        {onEdit && (
          <Button variant="outline" size="sm" onClick={() => onEdit(member.id)}>
            Edit
          </Button>
        )}
        {onAddLimit && (
          <Button variant="primary" size="sm" onClick={() => onAddLimit(member.id)}>
            Add Limit
          </Button>
        )}
        {member.status === 'ACTIVE' && onPause && (
          <Button variant="outline" size="sm" onClick={() => onPause(member.id)}>
            <PauseIcon className="h-4 w-4 mr-1" />
            Pause
          </Button>
        )}
        {member.status === 'PAUSED' && onResume && (
          <Button variant="outline" size="sm" onClick={() => onResume(member.id)}>
            <PlayIcon className="h-4 w-4 mr-1" />
            Resume
          </Button>
        )}
      </div>
    </Card>
  );
};

export default FamilyMemberCard;
