// Protected Route Component
const ProtectedRoute: React.FC<{
  children: React.ReactNode;
  allowedRoles?: ('PRIMARY' | 'LINKED')[];
}> = ({ children, allowedRoles }) => {
  const { isAuthenticated, user, isLoading } = useAuth();

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Navigate to="/" replace />;
  }

  if (allowedRoles && user && !allowedRoles.includes(user.role)) {
    return <Navigate to="/" replace />;
  }

  return <>{children}</>;
};

// Public Route (redirect if already authenticated)
const PublicRoute: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { isAuthenticated, isLoading } = useAuth();

  // Show loading while checking auth
  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  // Only redirect if definitely authenticated
  if (isAuthenticated) {
    return <Navigate to="/dashboard" replace />;
  }

  // Otherwise show the public content
  return <>{children}</>;
};

// Dashboard Redirect based on role
const DashboardRedirect = () => {
  const { user, isAuthenticated, isLoading } = useAuth();

  console.log('DashboardRedirect:', { user, isAuthenticated, isLoading }); // Debug log

  // Show loading while checking auth
  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  // If not authenticated, go to home
  if (!isAuthenticated) {
    return <Navigate to="/" replace />;
  }

  // If authenticated but no user role yet, stay on loading
  if (!user?.role) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  // Redirect based on role
  if (user.role === 'PRIMARY') {
    return <Navigate to="/primary/dashboard" replace />;
  }

  if (user.role === 'LINKED') {
    return <Navigate to="/linked/dashboard" replace />;
  }

  // Fallback
  return <Navigate to="/" replace />;
};

// Profile Redirect based on role
const ProfileRedirect = () => {
  const { user, isAuthenticated, isLoading } = useAuth();

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  if (!isAuthenticated || !user?.role) {
    return <Navigate to="/" replace />;
  }

  // Redirect based on role
  if (user.role === 'PRIMARY') {
    return <Navigate to="/primary/settings" replace />;
  }

  if (user.role === 'LINKED') {
    return <Navigate to="/linked/profile" replace />;
  }

  return <Navigate to="/" replace />;
};

