// BankDetails.tsx
import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  BuildingLibraryIcon,
  ArrowDownTrayIcon,
  DocumentDuplicateIcon,
  PencilIcon,
} from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import TransactionItem from '../../components/banking/TransactionItem';
import { useBank } from '../../hooks/useBank';
import toast from 'react-hot-toast';

const BankDetails: React.FC = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { getBankDetails, getBankTransactions, updateBank } = useBank();
  const [bank, setBank] = useState<any>(null);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, [id]);

  const loadData = async () => {
    setLoading(true);
    const bankData = await getBankDetails(id!);
    const txnData = await getBankTransactions(id!);
    setBank(bankData);
    setTransactions(txnData);
    setLoading(false);
  };

  const copyDetails = () => {
    const text = `Bank: ${bank.bankName}\nAccount: ${bank.accountNumber}\nIFSC: ${bank.ifscCode}`;
    navigator.clipboard.writeText(text);
    toast.success('Details copied!');
  };

  if (loading) return <div className="text-center py-8">Loading...</div>;

  return (
    <div>
      {/* Header */}
      <div className="flex justify-between items-start mb-6">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-primary-soft rounded-full flex items-center justify-center">
            <BuildingLibraryIcon className="h-8 w-8 text-primary" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">{bank.bankName}</h1>
            <p className="text-gray-600">{bank.accountNumber}</p>
            <p className="text-sm text-gray-500">IFSC: {bank.ifscCode}</p>
          </div>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={copyDetails}>
            <DocumentDuplicateIcon className="h-4 w-4 mr-1" /> Copy
          </Button>
          <Button variant="outline" size="sm" onClick={() => navigate(`/primary/banks/${id}/edit`)}>
            <PencilIcon className="h-4 w-4 mr-1" /> Edit
          </Button>
        </div>
      </div>

      {/* Details Card */}
      <Card className="mb-6">
        <div className="grid grid-cols-2 gap-6">
          <div>
            <p className="text-sm text-gray-500 mb-1">Account Holder</p>
            <p className="font-semibold">{bank.accountHolder}</p>
          </div>
          <div>
            <p className="text-sm text-gray-500 mb-1">Current Balance</p>
            <p className="text-2xl font-bold text-primary">₹{bank.balance.toLocaleString()}</p>
          </div>
          <div>
            <p className="text-sm text-gray-500 mb-1">Account Type</p>
            <p className="font-semibold capitalize">{bank.type || 'Savings'}</p>
          </div>
          <div>
            <p className="text-sm text-gray-500 mb-1">Status</p>
            <p className={`font-semibold ${bank.isVerified ? 'text-success' : 'text-warning'}`}>
              {bank.isVerified ? 'Verified' : 'Pending Verification'}
            </p>
          </div>
        </div>
      </Card>

      {/* Quick Actions */}
      <div className="grid grid-cols-3 gap-3 mb-6">
        <Button variant="outline" onClick={() => navigate(`/primary/send?bank=${id}`)}>
          Send Money
        </Button>
        <Button
          variant="outline"
          onClick={() => navigate('/wallet/add', { state: { bankId: id } })}
        >
          Add to Wallet
        </Button>
        <Button
          variant="outline"
          onClick={() => {
            /* Download statement */
          }}
        >
          <ArrowDownTrayIcon className="h-4 w-4 mr-1" /> Statement
        </Button>
      </div>

      {/* Recent Transactions */}
      <Card>
        <div className="flex justify-between items-center mb-4">
          <h3 className="font-semibold">Recent Transactions</h3>
          <Button
            variant="outline"
            size="sm"
            onClick={() => navigate(`/primary/transactions?bank=${id}`)}
          >
            View All
          </Button>
        </div>
        {transactions.map((txn) => (
          <TransactionItem key={txn.id} transaction={txn} />
        ))}
      </Card>
    </div>
  );
};

export default BankDetails;
