// services/api/family.ts
import apiClient from './client';

export const familyAPI = {
  // Primary routes
  getFamilyMembers: () => apiClient.get('/family'),
  getMemberById: (id: string) => apiClient.get(`/family/${id}`),
  inviteMember: (data: any) => apiClient.post('/family/invite', data),
  generateQR: () => apiClient.get('/family/qr'),
  generateInviteCode: () => apiClient.post('/family/generate-invite'),
  updateLimits: (memberId: string, data: any) => apiClient.put(`/family/${memberId}/limits`, data),
  addToLimit: (memberId: string, data: { amount: number }) =>
    apiClient.post(`/family/${memberId}/add-limit`, data),
  updateMemberStatus: (memberId: string, status: string) =>
    apiClient.put(`/family/${memberId}/status`, { status }),
  getMemberTransactions: (memberId: string, params?: any) =>
    apiClient.get(`/family/${memberId}/transactions`, { params }),

  // Linked routes
  connectToPrimary: (data: { method: string; code?: string; phone?: string }) => 
    apiClient.post('/family/connect', data),
  acceptInvite: (data: { inviteCode: string; phone: string }) =>
    apiClient.post('/family/accept', data),
  getMyLimits: () => apiClient.get('/family/me/limits'),
  getMyPrimaryDetails: () => apiClient.get('/family/my-primary'),
  createLimitRequest: (data: any) => apiClient.post('/family/requests', data),
  getRequests: () => apiClient.get('/family/requests'),
  approveRequest: (requestId: string) => apiClient.put(`/family/requests/${requestId}/approve`),
  denyRequest: (requestId: string) => apiClient.put(`/family/requests/${requestId}/deny`),
};