// AddBank.tsx
import React from 'react';
import { useNavigate } from 'react-router-dom';
import { BuildingLibraryIcon } from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';
import Card from '../../components/common/Card';
import AddBankForm from '../../components/banking/AddBankForm';
import { useBank } from '../../hooks/useBank';

const AddBank: React.FC = () => {
  const navigate = useNavigate();
  const { addBank, isLoading } = useBank();

  const handleSubmit = async (data: any) => {
    try {
      await addBank(data);
      toast.success('Bank account added!');
      navigate('/profile-setup');
    } catch (error: any) {
      toast.error(error.message || 'Failed to add bank');
    }
  };

  const handleSkip = () => {
    navigate('/profile-setup');
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        <AddBankForm onSubmit={handleSubmit} />

        <div className="text-center mt-4">
          <button onClick={handleSkip} className="text-gray-500 hover:text-gray-700 text-sm">
            Skip for now (you can add later)
          </button>
        </div>
      </div>
    </div>
  );
};

export default AddBank;
