// hooks/useFamily.ts
import { useState } from 'react';
import { familyAPI } from '../services/api/family';
import toast from 'react-hot-toast';

export const useFamily = () => {
  const [familyMembers, setFamilyMembers] = useState<any[]>([]);
  const [limits, setLimits] = useState<any>(null);
  const [requests, setRequests] = useState<any[]>([]);
  const [primaryDetails, setPrimaryDetails] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const getFamilyMembers = async () => {
    try {
      setLoading(true);
      const response = await familyAPI.getFamilyMembers();
      setFamilyMembers(response.data.members);
      return response.data;
    } catch (err) {
      toast.error('Failed to fetch family members');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const getMemberDetails = async (id: string) => {
    try {
      const response = await familyAPI.getMemberById(id);
      return response.data;
    } catch (err) {
      toast.error('Member not found');
      throw err;
    }
  };

  const inviteMember = async (data: any) => {
    try {
      setLoading(true);
      const response = await familyAPI.inviteMember(data);
      toast.success('Invitation sent successfully');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Failed to send invite');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const generateQR = async () => {
    try {
      const response = await familyAPI.generateQR();
      return response.data;
    } catch (err) {
      toast.error('Failed to generate QR');
      throw err;
    }
  };

  const acceptInvite = async (inviteCode: string, phone: string) => {
    try {
      setLoading(true);
      const response = await familyAPI.acceptInvite({ inviteCode, phone });
      toast.success('Successfully joined family');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Invalid invite');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const updateLimits = async (memberId: string, limits: any) => {
    try {
      setLoading(true);
      const response = await familyAPI.updateLimits(memberId, limits);
      await getFamilyMembers();
      toast.success('Limits updated successfully');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Update failed');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const addToLimit = async (memberId: string, amount: number) => {
    try {
      setLoading(true);
      const response = await familyAPI.addToLimit(memberId, { amount });
      await getFamilyMembers();
      toast.success(`₹${amount} added to limit`);
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Failed to add');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const updateMemberStatus = async (memberId: string, status: string) => {
    try {
      const response = await familyAPI.updateMemberStatus(memberId, status);
      await getFamilyMembers();
      toast.success(`Member ${status.toLowerCase()}`);
      return response.data;
    } catch (err: any) {
      toast.error('Status update failed');
      throw err;
    }
  };

  const pauseMember = (memberId: string) => updateMemberStatus(memberId, 'PAUSED');
  const resumeMember = (memberId: string) => updateMemberStatus(memberId, 'ACTIVE');

  // Linked user functions
  const getPrimaryDetails = async () => {
    try {
      setLoading(true);
      const response = await familyAPI.getMyPrimaryDetails();
      setPrimaryDetails(response.data.primary);
      setLimits(response.data.limits);
      return response.data;
    } catch (err) {
      console.error('Failed to fetch primary details:', err);
      toast.error('Could not load family details');
      return null;
    } finally {
      setLoading(false);
    }
  };

  const getMyLimits = async () => {
    try {
      const response = await familyAPI.getMyLimits();
      setLimits(response.data);
      return response.data;
    } catch (err) {
      return null;
    }
  };

  const createLimitRequest = async (data: any) => {
    try {
      setLoading(true);
      const response = await familyAPI.createLimitRequest(data);
      toast.success('Request sent to primary account');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Request failed');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const getRequests = async () => {
    try {
      const response = await familyAPI.getRequests();
      setRequests(response.data);
      return response.data;
    } catch (err) {
      return [];
    }
  };

  const approveRequest = async (requestId: string) => {
    try {
      const response = await familyAPI.approveRequest(requestId);
      await getRequests();
      toast.success('Request approved');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Approval failed');
      throw err;
    }
  };

  const denyRequest = async (requestId: string) => {
    try {
      const response = await familyAPI.denyRequest(requestId);
      await getRequests();
      toast.success('Request denied');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Failed to deny');
      throw err;
    }
  };

  return {
    familyMembers,
    limits,
    requests,
    primaryDetails,
    loading,
    getFamilyMembers,
    getMemberDetails,
    inviteMember,
    generateQR,
    acceptInvite,
    updateLimits,
    addToLimit,
    pauseMember,
    resumeMember,
    updateMemberStatus,
    getPrimaryDetails,
    getMyLimits,
    createLimitRequest,
    getRequests,
    approveRequest,
    denyRequest,
  };
};