// RequestIncrease.tsx
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { ArrowTrendingUpIcon, CheckCircleIcon } from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';
import Card from '../../components/common/Card';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { useFamily } from '../../hooks/useFamily';

const requestSchema = z.object({
  amount: z.number().min(1, 'Amount is required').max(10000, 'Max ₹10,000'),
  reason: z.string().optional(),
  duration: z.enum(['today', 'week', 'permanent']),
});

type RequestFormData = z.infer<typeof requestSchema>;

const RequestIncrease: React.FC = () => {
  const navigate = useNavigate();
  const { createLimitRequest, limits } = useFamily();
  const [submitted, setSubmitted] = useState(false);
  const {
    register,
    handleSubmit,
    watch,
    setValue,
    formState: { errors, isSubmitting },
  } = useForm<RequestFormData>({
    resolver: zodResolver(requestSchema),
    defaultValues: { duration: 'today' },
  });

  const amount = watch('amount');
  const duration = watch('duration');

  const onSubmit = async (data: RequestFormData) => {
    try {
      await createLimitRequest(data);
      setSubmitted(true);
      toast.success('Request sent to primary account');
    } catch (error: any) {
      toast.error(error.message);
    }
  };

  if (submitted) {
    return (
      <div className="max-w-md mx-auto">
        <Card className="text-center">
          <CheckCircleIcon className="h-16 w-16 text-success mx-auto mb-4" />
          <h2 className="text-2xl font-bold mb-2">Request Sent!</h2>
          <p className="text-gray-600 mb-6">
            Your primary account holder will review your request.
          </p>
          <Button onClick={() => navigate('/linked/dashboard')}>Back to Dashboard</Button>
        </Card>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Request Limit Increase</h1>

      {/* Current Limits */}
      <Card className="mb-6 bg-gray-50">
        <h2 className="font-semibold mb-3">Current Limits</h2>
        <div className="grid grid-cols-2 gap-4">
          <div>
            <p className="text-sm text-gray-600">Daily</p>
            <p className="text-lg font-bold">
              ₹{limits?.dailySpent} / ₹{limits?.dailyLimit}
            </p>
          </div>
          <div>
            <p className="text-sm text-gray-600">Monthly</p>
            <p className="text-lg font-bold">
              ₹{limits?.monthlySpent} / ₹{limits?.monthlyLimit}
            </p>
          </div>
          <div>
            <p className="text-sm text-gray-600">Per Transaction</p>
            <p className="text-lg font-bold">₹{limits?.perTransactionLimit}</p>
          </div>
        </div>
      </Card>

      <Card>
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
          <div>
            <Input
              label="Additional Amount Needed (₹)"
              type="number"
              placeholder="Enter amount"
              {...register('amount', { valueAsNumber: true })}
              error={errors.amount?.message}
            />
            <p className="text-xs text-gray-500 mt-1">Max ₹10,000 per request</p>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Duration</label>
            <div className="grid grid-cols-3 gap-3">
              {[
                { value: 'today', label: 'Just Today' },
                { value: 'week', label: 'This Week' },
                { value: 'permanent', label: 'Permanent' },
              ].map((option) => (
                <button
                  key={option.value}
                  type="button"
                  onClick={() => setValue('duration', option.value as any)}
                  className={`p-3 rounded-lg border-2 transition-colors ${
                    duration === option.value
                      ? 'border-primary bg-primary-soft'
                      : 'border-gray-200 hover:border-gray-300'
                  }`}
                >
                  <span
                    className={`text-sm ${
                      duration === option.value ? 'text-primary font-medium' : 'text-gray-600'
                    }`}
                  >
                    {option.label}
                  </span>
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Reason (Optional)
            </label>
            <textarea
              {...register('reason')}
              placeholder="Tell your primary account why you need this increase..."
              rows={4}
              className="w-full p-3 border rounded-lg focus:border-primary focus:outline-none"
            />
          </div>

          <Button type="submit" fullWidth size="lg" loading={isSubmitting}>
            Send Request
          </Button>
        </form>
      </Card>
    </div>
  );
};

export default RequestIncrease;
