// Transactions.tsx
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { FunnelIcon, ArrowPathIcon } from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import TransactionItem from '../../components/banking/TransactionItem';
import { useWallet } from '../../hooks/useWallet';

const Transactions: React.FC = () => {
  const navigate = useNavigate();
  const { transactions, loading, getTransactions, getTransactionStats } = useWallet();
  const [stats, setStats] = useState({ total: 0, sent: 0, received: 0, recharge: 0 });
  const [filters, setFilters] = useState({
    type: '',
    startDate: '',
    endDate: '',
    search: '',
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    await getTransactions();
    const data = await getTransactionStats();
    setStats(data as any);
  };

  const filteredTransactions = transactions?.filter((txn) => {
    if (filters.type && txn.type !== filters.type) return false;
    if (filters.search) {
      const searchLower = filters.search.toLowerCase();
      return (
        txn.description?.toLowerCase().includes(searchLower) ||
        txn.transactionId.toLowerCase().includes(searchLower)
      );
    }
    return true;
  });

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Transactions</h1>
        <Button variant="outline" size="sm" onClick={loadData}>
          <ArrowPathIcon className="h-4 w-4 mr-1" /> Refresh
        </Button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-4 gap-4 mb-6">
        <Card className="text-center">
          <p className="text-sm text-gray-600">Total</p>
          <p className="text-xl font-bold">{stats.total}</p>
        </Card>
        <Card className="text-center">
          <p className="text-sm text-gray-600">Sent</p>
          <p className="text-xl font-bold text-error">{stats.sent}</p>
        </Card>
        <Card className="text-center">
          <p className="text-sm text-gray-600">Received</p>
          <p className="text-xl font-bold text-success">{stats.received}</p>
        </Card>
        <Card className="text-center">
          <p className="text-sm text-gray-600">Recharge</p>
          <p className="text-xl font-bold">{stats.recharge}</p>
        </Card>
      </div>

      {/* Filters */}
      <Card className="mb-6">
        <div className="flex items-center gap-2 mb-4">
          <FunnelIcon className="h-5 w-5 text-gray-500" />
          <h2 className="font-semibold">Filters</h2>
        </div>
        <div className="grid md:grid-cols-4 gap-4">
          <select
            value={filters.type}
            onChange={(e) => setFilters({ ...filters, type: e.target.value })}
            className="p-2 border rounded-lg"
          >
            <option value="">All Types</option>
            <option value="SEND">Sent</option>
            <option value="RECEIVE">Received</option>
            <option value="RECHARGE">Recharge</option>
            <option value="ADD_TO_WALLET">Added to Wallet</option>
          </select>
          <Input
            type="date"
            placeholder="Start Date"
            value={filters.startDate}
            onChange={(e) => setFilters({ ...filters, startDate: e.target.value })}
          />
          <Input
            type="date"
            placeholder="End Date"
            value={filters.endDate}
            onChange={(e) => setFilters({ ...filters, endDate: e.target.value })}
          />
          <Input
            placeholder="Search by ID or description"
            value={filters.search}
            onChange={(e) => setFilters({ ...filters, search: e.target.value })}
          />
        </div>
      </Card>

      {/* Transactions List */}
      <Card>
        {loading ? (
          <div className="text-center py-8">Loading...</div>
        ) : filteredTransactions?.length === 0 ? (
          <div className="text-center py-8 text-gray-500">No transactions found</div>
        ) : (
          filteredTransactions?.map((txn) => (
            <TransactionItem
              key={txn.id}
              transaction={txn}
              onClick={() => navigate(`/primary/transactions/${txn.id}`)}
            />
          ))
        )}
      </Card>
    </div>
  );
};

export default Transactions;
