// recharge.ts
import apiClient from './client';

export const rechargeAPI = {
  getPlans: (params?: any) => apiClient.get('/recharge/plans', { params }),
  mobileRecharge: (data: any) => apiClient.post('/recharge/mobile', data),
  electricityBill: (data: any) => apiClient.post('/recharge/electricity', data),
  fastagRecharge: (data: any) => apiClient.post('/recharge/fastag', data),
  getHistory: (params?: any) => apiClient.get('/recharge/history', { params }),
};
