// LinkedHistory.tsx
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { FunnelIcon, ClockIcon } from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Input from '../../components/common/Input';
import TransactionItem from '../../components/banking/TransactionItem';
import { useWallet } from '../../hooks/useWallet';

const LinkedHistory: React.FC = () => {
  const navigate = useNavigate();
  const { transactions, loading, getTransactions } = useWallet();
  const [filter, setFilter] = useState({
    type: '',
    search: '',
  });

  useEffect(() => {
    getTransactions();
  }, []);

  const filteredTransactions = transactions?.filter((txn) => {
    if (filter.type && txn.type !== filter.type) return false;
    if (filter.search) {
      return (
        txn.description?.toLowerCase().includes(filter.search.toLowerCase()) ||
        txn.transactionId.toLowerCase().includes(filter.search)
      );
    }
    return true;
  });

  return (
    <div>
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Transaction History</h1>

      {/* Filters */}
      <Card className="mb-6">
        <div className="flex items-center gap-4">
          <div className="flex-1">
            <Input
              placeholder="Search transactions..."
              value={filter.search}
              onChange={(e) => setFilter({ ...filter, search: e.target.value })}
            />
          </div>
          <select
            value={filter.type}
            onChange={(e) => setFilter({ ...filter, type: e.target.value })}
            className="p-2 border rounded-lg"
          >
            <option value="">All</option>
            <option value="SEND">Sent</option>
            <option value="PAYMENT">QR Payments</option>
            <option value="RECHARGE">Recharges</option>
          </select>
        </div>
      </Card>

      {/* Stats Summary */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        <Card className="text-center">
          <p className="text-sm text-gray-600">Total</p>
          <p className="text-xl font-bold">{transactions?.length || 0}</p>
        </Card>
        <Card className="text-center">
          <p className="text-sm text-gray-600">This Month</p>
          <p className="text-xl font-bold">
            {
              transactions?.filter(
                (t) => new Date(t.createdAt).getMonth() === new Date().getMonth(),
              ).length
            }
          </p>
        </Card>
        <Card className="text-center">
          <p className="text-sm text-gray-600">Total Spent</p>
          <p className="text-xl font-bold">
            ₹{transactions?.reduce((sum, t) => sum + t.amount, 0)}
          </p>
        </Card>
      </div>

      {/* Transactions List */}
      <Card>
        {loading ? (
          <div className="text-center py-8">Loading...</div>
        ) : filteredTransactions?.length === 0 ? (
          <div className="text-center py-12">
            <ClockIcon className="h-12 w-12 text-gray-300 mx-auto mb-3" />
            <p className="text-gray-500">No transactions yet</p>
          </div>
        ) : (
          filteredTransactions?.map((txn) => (
            <TransactionItem
              key={txn.id}
              transaction={txn}
              onClick={() => navigate(`/linked/history/${txn.id}`)}
            />
          ))
        )}
      </Card>
    </div>
  );
};

export default LinkedHistory;
