// FamilyManagement.tsx
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { PlusIcon, MagnifyingGlassIcon } from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import FamilyMemberCard from '../../components/family/FamilyMemberCard';
import { useFamily } from '../../hooks/useFamily';

const FamilyManagement: React.FC = () => {
  const navigate = useNavigate();
  const { familyMembers, loading, getFamilyMembers, updateMemberStatus } = useFamily();
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState<'all' | 'active' | 'paused'>('all');

  useEffect(() => {
    getFamilyMembers();
  }, []);

  const filteredMembers = familyMembers?.filter((member) => {
    if (filter !== 'all' && member.status.toLowerCase() !== filter) return false;
    if (search) {
      return (
        member.name.toLowerCase().includes(search.toLowerCase()) || member.phone.includes(search)
      );
    }
    return true;
  });

  const handlePause = async (id: string) => {
    await updateMemberStatus(id, 'PAUSED');
    getFamilyMembers();
  };

  const handleResume = async (id: string) => {
    await updateMemberStatus(id, 'ACTIVE');
    getFamilyMembers();
  };

  const stats = {
    total: familyMembers?.length || 0,
    active: familyMembers?.filter((m) => m.status === 'ACTIVE').length || 0,
    totalSpent: familyMembers?.reduce((sum, m) => sum + m.dailySpent, 0) || 0,
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Family Management</h1>
        <Button onClick={() => navigate('/primary/family/add')}>
          <PlusIcon className="h-4 w-4 mr-1" /> Add Member
        </Button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        <Card className="text-center">
          <p className="text-sm text-gray-600">Total Members</p>
          <p className="text-2xl font-bold text-primary">{stats.total}</p>
        </Card>
        <Card className="text-center">
          <p className="text-sm text-gray-600">Active</p>
          <p className="text-2xl font-bold text-success">{stats.active}</p>
        </Card>
        <Card className="text-center">
          <p className="text-sm text-gray-600">Today's Spend</p>
          <p className="text-2xl font-bold">₹{stats.totalSpent}</p>
        </Card>
      </div>

      {/* Filters */}
      <Card className="mb-6">
        <div className="flex gap-4">
          <div className="flex-1">
            <Input
              placeholder="Search by name or phone"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              icon={<MagnifyingGlassIcon className="h-5 w-5" />}
            />
          </div>
          <div className="flex gap-2">
            {['all', 'active', 'paused'].map((f) => (
              <button
                key={f}
                onClick={() => setFilter(f as any)}
                className={`px-4 py-2 rounded-lg capitalize ${
                  filter === f
                    ? 'bg-primary text-white'
                    : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                }`}
              >
                {f}
              </button>
            ))}
          </div>
        </div>
      </Card>

      {/* Members List */}
      <div className="grid md:grid-cols-2 gap-4">
        {loading ? (
          <div className="col-span-2 text-center py-8">Loading...</div>
        ) : filteredMembers?.length === 0 ? (
          <div className="col-span-2 text-center py-8 text-gray-500">No family members found</div>
        ) : (
          filteredMembers?.map((member) => (
            <FamilyMemberCard
              key={member.id}
              member={member}
              onView={(id) => navigate(`/primary/family/${id}`)}
              onEdit={(id) => navigate(`/primary/family/${id}/edit`)}
              onPause={member.status === 'ACTIVE' ? handlePause : undefined}
              onResume={member.status === 'PAUSED' ? handleResume : undefined}
              onAddLimit={(id) => navigate(`/primary/family/${id}/add-limit`)}
            />
          ))
        )}
      </div>
    </div>
  );
};

export default FamilyManagement;
