// Notifications.tsx
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { BellIcon, CheckCircleIcon, XMarkIcon, ClockIcon } from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import { useNotifications } from '../../hooks/useNotifications';

const Notifications: React.FC = () => {
  const navigate = useNavigate();
  const {
    notifications,
    loading,
    markAsRead,
    markAllAsRead,
    deleteNotification,
  } = useNotifications();
  const [filter, setFilter] = useState<'all' | 'unread'>('all');

  const filtered = filter === 'all' ? notifications : notifications?.filter((n) => !n.isRead);

  const getIcon = (type: string) => {
    switch (type) {
      case 'PAYMENT_SUCCESS':
        return <CheckCircleIcon className="h-5 w-5 text-success" />;
      case 'PAYMENT_FAILED':
        return <XMarkIcon className="h-5 w-5 text-error" />;
      case 'LIMIT_REQUEST':
        return <ClockIcon className="h-5 w-5 text-warning" />;
      default:
        return <BellIcon className="h-5 w-5 text-primary" />;
    }
  };

  const handleNotificationClick = async (notification: any) => {
    if (!notification.isRead) await markAsRead(notification.id);
    if (notification.data?.path) navigate(notification.data.path);
  };

  return (
    <div className="max-w-3xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Notifications</h1>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => markAllAsRead()}>
            Mark All Read
          </Button>
          <select
            value={filter}
            onChange={(e) => setFilter(e.target.value as any)}
            className="p-2 border rounded-lg"
          >
            <option value="all">All</option>
            <option value="unread">Unread</option>
          </select>
        </div>
      </div>

      <Card>
        {loading ? (
          <div className="text-center py-8">Loading...</div>
        ) : filtered?.length === 0 ? (
          <div className="text-center py-12">
            <BellIcon className="h-12 w-12 text-gray-300 mx-auto mb-3" />
            <p className="text-gray-500">No notifications</p>
          </div>
        ) : (
          <div className="divide-y">
            {filtered?.map((notification) => (
              <div
                key={notification.id}
                onClick={() => handleNotificationClick(notification)}
                className={`p-4 hover:bg-gray-50 cursor-pointer transition-colors ${
                  !notification.isRead ? 'bg-primary-soft' : ''
                }`}
              >
                <div className="flex gap-3">
                  <div className="flex-shrink-0">{getIcon(notification.type)}</div>
                  <div className="flex-1">
                    <p
                      className={`font-medium ${!notification.isRead ? 'text-gray-900' : 'text-gray-600'}`}
                    >
                      {notification.title}
                    </p>
                    <p className="text-sm text-gray-500 mt-1">{notification.message}</p>
                    <p className="text-xs text-gray-400 mt-2">
                      {new Date(notification.createdAt).toLocaleString()}
                    </p>
                  </div>
                  {!notification.isRead && <div className="w-2 h-2 bg-primary rounded-full" />}
                </div>
              </div>
            ))}
          </div>
        )}
      </Card>
    </div>
  );
};

export default Notifications;
