// BankAccounts.tsx
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { PlusIcon, BuildingLibraryIcon } from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import BankCard from '../../components/banking/BankCard';
import { useBank } from '../../hooks/useBank';

const BankAccounts: React.FC = () => {
  const navigate = useNavigate();
  const { banks, loading, getBanks, setDefaultBank, removeBank, verifyBank } = useBank();
  const [totalBalance, setTotalBalance] = useState(0);

  useEffect(() => {
    loadBanks();
  }, []);

  const loadBanks = async () => {
    const data = await getBanks();
    setTotalBalance(data.reduce((sum: number, b: any) => sum + b.balance, 0));
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Bank Accounts</h1>
        <Button onClick={() => navigate('/primary/banks/add')}>
          <PlusIcon className="h-4 w-4 mr-1" /> Add Bank
        </Button>
      </div>

      {/* Summary */}
      <Card className="mb-6 bg-primary text-white">
        <div className="flex items-center gap-3">
          <BuildingLibraryIcon className="h-8 w-8" />
          <div>
            <p className="text-sm opacity-90">Total Balance</p>
            <p className="text-3xl font-bold">₹{totalBalance.toLocaleString()}</p>
            <p className="text-xs opacity-75 mt-1">{banks?.length || 0} linked accounts</p>
          </div>
        </div>
      </Card>

      {/* Bank List */}
      <div className="space-y-4">
        {loading ? (
          <div className="text-center py-8">Loading...</div>
        ) : banks?.length === 0 ? (
          <Card className="text-center py-12">
            <BuildingLibraryIcon className="h-12 w-12 text-gray-300 mx-auto mb-3" />
            <h3 className="text-lg font-medium text-gray-700 mb-2">No banks linked</h3>
            <p className="text-gray-500 mb-4">Add your first bank account to get started</p>
            <Button onClick={() => navigate('/primary/banks/add')}>Add Bank Account</Button>
          </Card>
        ) : (
          banks?.map((bank) => (
            <BankCard
              key={bank.id}
              bank={bank}
              onSend={(id) => navigate(`/primary/send?bank=${id}`)}
              onSetDefault={setDefaultBank}
              onRemove={removeBank}
              onVerify={verifyBank}
            />
          ))
        )}
      </div>
    </div>
  );
};

export default BankAccounts;
