import apiClient from './client';

export const walletAPI = {
  getBalance: () => apiClient.get('/wallet/balance'),
  getTransactions: (params?: any) => apiClient.get('/wallet/transactions', { params }),
  addMoney: (data: any) => apiClient.post('/wallet/add', data),
  withdrawMoney: (data: any) => apiClient.post('/wallet/withdraw', data),
  getStats: () => apiClient.get('/wallet/stats'),
  getMemberTransactions: (memberId: string) => apiClient.get(`/family/${memberId}/transactions`),
};
