// useBank.ts
import { useState } from 'react';
import { bankAPI } from '../services/api/banks';
import toast from 'react-hot-toast';

export const useBank = () => {
  const [banks, setBanks] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  const getBanks = async () => {
    try {
      setLoading(true);
      const response = await bankAPI.getBanks();
      setBanks(response.data.banks);
      return response.data;
    } catch (err) {
      toast.error('Failed to fetch banks');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const addBank = async (data: any) => {
    try {
      setLoading(true);
      const response = await bankAPI.addBank(data);
      await getBanks();
      toast.success('Bank account added successfully');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Failed to add bank');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const updateBank = async (id: string, data: any) => {
    try {
      setLoading(true);
      const response = await bankAPI.updateBank(id, data);
      await getBanks();
      toast.success('Bank updated successfully');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Update failed');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const removeBank = async (id: string) => {
    if (!confirm('Remove this bank account?')) return;
    try {
      await bankAPI.deleteBank(id);
      await getBanks();
      toast.success('Bank removed');
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Failed to remove');
    }
  };

  const setDefaultBank = async (id: string) => {
    try {
      await bankAPI.updateBank(id, { isDefault: true });
      await getBanks();
      toast.success('Default bank updated');
    } catch (err: any) {
      toast.error('Failed to set default');
    }
  };

  const verifyBank = async (id: string) => {
    try {
      const response = await bankAPI.verifyBank(id);
      await getBanks();
      toast.success('Bank verified successfully');
      return response.data;
    } catch (err: any) {
      toast.error('Verification failed');
      throw err;
    }
  };

  const getBankDetails = async (id: string) => {
    try {
      const response = await bankAPI.getBankById(id);
      return response.data;
    } catch (err) {
      toast.error('Bank not found');
      throw err;
    }
  };

  const getBankTransactions = async (id: string) => {
    try {
      const response = await bankAPI.getBankTransactions(id);
      return response.data;
    } catch (err) {
      return [];
    }
  };

  return {
    banks,
    loading,
    isLoading: loading,
    getBanks,
    addBank,
    updateBank,
    removeBank,
    setDefaultBank,
    verifyBank,
    getBankDetails,
    getBankTransactions,
  };
};
