// Settings.tsx
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  UserIcon,
  BellIcon,
  LockClosedIcon,
  LanguageIcon,
  MoonIcon,
  InformationCircleIcon,
  ArrowRightOnRectangleIcon,
  ShieldCheckIcon,
  DocumentTextIcon,
} from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import { useAuth } from '../../hooks/useAuth';

// Define the SettingsItem type
type SettingsItem = {
  icon: React.ElementType;
  label: string;
  path?: string;
  value?: string;
  isToggle?: boolean;
  toggleValue?: boolean;
  onToggle?: (value: boolean) => void;
};

const Settings: React.FC = () => {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const [darkMode, setDarkMode] = useState(false);

  // Add type annotation to settingsSections
  const settingsSections: {
    title: string;
    items: SettingsItem[];
  }[] = [
    {
      title: 'Account',
      items: [
        { icon: UserIcon, label: 'Profile Information', path: '/primary/Settings/PrimaryProfile' },
        { icon: LockClosedIcon, label: 'Change PIN', path: '/primary/Settings/PrimarySecurity' },
        { icon: BellIcon, label: 'Notifications', path: '/primary/Settings/PrimaryNotifications' },
      ],
    },
    {
      title: 'Preferences',
      items: [
        { icon: LanguageIcon, label: 'Language', value: 'English', path: '/language' },
        {
          icon: MoonIcon,
          label: 'Dark Mode',
          isToggle: true,
          toggleValue: darkMode,
          onToggle: setDarkMode,
        },
      ],
    },
    {
      title: 'Support',
      items: [
        { icon: InformationCircleIcon, label: 'About', value: 'Version 1.0.0', path: '/about' },
        { icon: DocumentTextIcon, label: 'Terms of Service', path: '/terms' },
        { icon: ShieldCheckIcon, label: 'Privacy Policy', path: '/privacy' },
      ],
    },
    {
      title: 'Account',
      items: [
        { icon: UserIcon, label: 'Profile Information', path: '/primary/settings/profile' },
        { icon: LockClosedIcon, label: 'Change PIN', path: '/primary/settings/security' },
        { icon: BellIcon, label: 'Notifications', path: '/primary/settings/notifications' },
      ],
    },

  ];

  const handleLogout = async () => {
    if (confirm('Are you sure you want to logout?')) {
      await logout();
      navigate('/');
    }
  };

  return (
    <div className="max-w-2xl mx-auto">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Settings</h1>

      {/* Profile Summary */}
      <Card className="mb-6 flex items-center gap-4">
        <div className="w-16 h-16 bg-primary-soft rounded-full flex items-center justify-center">
          <UserIcon className="h-8 w-8 text-primary" />
        </div>
        <div>
          <h2 className="font-semibold text-lg">{user?.name || 'User'}</h2>
          <p className="text-gray-600">{user?.phone}</p>
          <p className="text-sm text-gray-500 capitalize">{user?.role} Account</p>
        </div>
        <Button
          variant="outline"
          size="sm"
          className="ml-auto"
          onClick={() => navigate('/profile')}
        >
          Edit
        </Button>
      </Card>

      {/* Settings Sections */}
      {settingsSections.map((section, idx) => (
        <Card key={idx} className="mb-4">
          <h3 className="font-semibold text-gray-700 mb-3">{section.title}</h3>
          <div className="divide-y">
            {section.items.map((item, i) => (
              <div
                key={i}
                className="py-3 flex items-center justify-between cursor-pointer hover:bg-gray-50"
                onClick={() => !item.isToggle && item.path && navigate(item.path)}
              >
                <div className="flex items-center gap-3">
                  <item.icon className="h-5 w-5 text-gray-500" />
                  <span className="text-gray-700">{item.label}</span>
                </div>
                {item.isToggle ? (
                  <label className="relative inline-flex items-center cursor-pointer">
                    <input
                      type="checkbox"
                      checked={item.toggleValue}
                      onChange={(e) => item.onToggle?.(e.target.checked)}
                      className="sr-only peer"
                    />
                    <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-primary"></div>
                  </label>
                ) : (
                  <div className="flex items-center gap-2">
                    {item.value && <span className="text-sm text-gray-500">{item.value}</span>}
                    <span className="text-gray-400">›</span>
                  </div>
                )}
              </div>
            ))}
          </div>
        </Card>
      ))}

      {/* Logout Button */}
      <Button
        variant="outline"
        fullWidth
        size="lg"
        onClick={handleLogout}
        className="border-error text-error hover:bg-error-soft"
      >
        <ArrowRightOnRectangleIcon className="h-5 w-5 mr-2" />
        Logout
      </Button>

      <p className="text-center text-xs text-gray-400 mt-6">SnapPay v1.0.0</p>
    </div>
  );
};

export default Settings;