// useSocket.ts
import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
import { useAuth } from './useAuth';
import toast from 'react-hot-toast';

let socket: Socket | null = null;

export const useSocket = () => {
  const { user, isAuthenticated } = useAuth();
  const [isConnected, setIsConnected] = useState(false);
  const [notifications, setNotifications] = useState<any[]>([]);

  useEffect(() => {
    if (!isAuthenticated || !user) return;

    // FIXED: Use import.meta.env instead of process.env
    const socketUrl = import.meta.env.VITE_SOCKET_URL || 'http://localhost:5000';

    // Initialize socket connection
    socket = io(socketUrl, {
      auth: { token: localStorage.getItem('token') },
      transports: ['websocket', 'polling'],
    });

    socket.on('connect', () => {
      console.log('Socket connected');
      setIsConnected(true);
    });

    socket.on('disconnect', () => {
      console.log('Socket disconnected');
      setIsConnected(false);
    });

    socket.on('notification', (notification) => {
      setNotifications((prev) => [notification, ...prev]);

      // Show toast for new notifications
      toast(notification.message, {
        icon: getNotificationIcon(notification.type),
        duration: 5000,
      });
    });

    socket.on('limit-updated', (data) => {
      toast.success(`Limit updated: ${data.message}`);
    });

    socket.on('payment-received', (data) => {
      toast.success(`💰 Received ₹${data.amount} from ${data.from}`);
    });

    socket.on('request-approved', (data) => {
      toast.success('Your limit request was approved!');
    });

    socket.on('request-denied', () => {
      toast.error('Your limit request was denied');
    });

    // Join user room
    socket.emit('join-user', user.id);

    if (user.role === 'PRIMARY') {
      socket.emit('join-primary', user.id);
    }

    return () => {
      if (socket) {
        socket.disconnect();
        socket = null;
      }
    };
  }, [isAuthenticated, user?.id]);

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case 'PAYMENT_SUCCESS':
        return '✅';
      case 'PAYMENT_FAILED':
        return '❌';
      case 'LIMIT_REQUEST':
        return '📊';
      case 'LIMIT_APPROVED':
        return '👍';
      case 'LIMIT_DENIED':
        return '👎';
      default:
        return '🔔';
    }
  };

  const emit = (event: string, data: any) => {
    if (socket && isConnected) {
      socket.emit(event, data);
    }
  };

  const joinFamilyRoom = (familyId: string) => {
    emit('join-family', familyId);
  };

  const sendTyping = (to: string, isTyping: boolean) => {
    emit('typing', { to, isTyping });
  };

  const clearNotifications = () => {
    setNotifications([]);
  };

  return {
    socket,
    isConnected,
    notifications,
    emit,
    joinFamilyRoom,
    sendTyping,
    clearNotifications,
  };
};
