// LimitSetter.tsx
import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { AdjustmentsHorizontalIcon } from '@heroicons/react/24/outline';
import Card from '../common/Card';
import Input from '../common/Input';
import Button from '../common/Button';

const limitSchema = z.object({
  dailyLimit: z.number().min(1, 'Daily limit required').max(10000, 'Max ₹10,000'),
  monthlyLimit: z.number().min(1, 'Monthly limit required').max(50000, 'Max ₹50,000'),
  perTransactionLimit: z.number().min(1, 'Per transaction limit required').max(1000, 'Max ₹1,000'),
  sendMoney: z.boolean().default(true),
  scanPay: z.boolean().default(true),
  recharge: z.boolean().default(true),
  viewHistory: z.boolean().default(true),
});

type LimitFormData = z.infer<typeof limitSchema>;

interface LimitSetterProps {
  memberName?: string;
  initialValues?: Partial<LimitFormData>;
  onSubmit: (data: LimitFormData) => Promise<void>;
  onCancel?: () => void;
}

const LimitSetter: React.FC<LimitSetterProps> = ({
  memberName,
  initialValues,
  onSubmit,
  onCancel,
}) => {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const {
    register,
    handleSubmit,
    watch,
    setValue,
    formState: { errors },
  } = useForm<LimitFormData>({
    resolver: zodResolver(limitSchema),
    defaultValues: {
      dailyLimit: 500,
      monthlyLimit: 5000,
      perTransactionLimit: 200,
      sendMoney: true,
      scanPay: true,
      recharge: true,
      viewHistory: true,
      ...initialValues,
    },
  });

  const quickAmounts = [100, 200, 500, 1000, 2000, 5000];

  const handleQuickAmount = (amount: number, field: 'dailyLimit' | 'monthlyLimit') => {
    setValue(field, amount, { shouldValidate: true });
  };

  const handleFormSubmit = async (data: LimitFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card>
      <div className="flex items-center gap-3 mb-6">
        <AdjustmentsHorizontalIcon className="h-8 w-8 text-primary" />
        <h2 className="text-2xl font-bold text-gray-900">
          {memberName ? `Set Limits for ${memberName}` : 'Set Spending Limits'}
        </h2>
      </div>

      <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Daily Limit</label>
          <Input
            type="number"
            placeholder="Enter daily limit"
            error={errors.dailyLimit?.message}
            {...register('dailyLimit', { valueAsNumber: true })}
          />
          <div className="flex gap-2 mt-2">
            {quickAmounts.map((amount) => (
              <button
                key={amount}
                type="button"
                onClick={() => handleQuickAmount(amount, 'dailyLimit')}
                className="px-2 py-1 bg-gray-100 hover:bg-primary-soft text-xs rounded"
              >
                ₹{amount}
              </button>
            ))}
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Monthly Limit</label>
          <Input
            type="number"
            placeholder="Enter monthly limit"
            error={errors.monthlyLimit?.message}
            {...register('monthlyLimit', { valueAsNumber: true })}
          />
          <div className="flex gap-2 mt-2">
            {quickAmounts.map((amount) => (
              <button
                key={amount}
                type="button"
                onClick={() => handleQuickAmount(amount * 10, 'monthlyLimit')}
                className="px-2 py-1 bg-gray-100 hover:bg-primary-soft text-xs rounded"
              >
                ₹{amount * 10}
              </button>
            ))}
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Per Transaction Limit
          </label>
          <Input
            type="number"
            placeholder="Enter per transaction limit"
            error={errors.perTransactionLimit?.message}
            {...register('perTransactionLimit', { valueAsNumber: true })}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-3">Permissions</label>
          <div className="space-y-2">
            {[
              { id: 'sendMoney', label: 'Send Money to Mobile' },
              { id: 'scanPay', label: 'Scan & Pay at Shops' },
              { id: 'recharge', label: 'Recharge (Mobile/Electricity)' },
              { id: 'viewHistory', label: 'View Transaction History' },
            ].map((perm) => (
              <label key={perm.id} className="flex items-center gap-2">
                <input
                  type="checkbox"
                  {...register(perm.id as any)}
                  className="w-4 h-4 text-primary rounded border-gray-300"
                />
                <span className="text-sm text-gray-700">{perm.label}</span>
              </label>
            ))}
          </div>
        </div>

        <div className="flex gap-3 pt-4">
          <Button type="submit" loading={isSubmitting} className="flex-1">
            Save Limits
          </Button>
          {onCancel && (
            <Button type="button" variant="outline" onClick={onCancel} className="flex-1">
              Cancel
            </Button>
          )}
        </div>
      </form>
    </Card>
  );
};

export default LimitSetter;
