// payments.ts
import apiClient from './client';

export const paymentAPI = {
  sendToMobile: (data: { toMobile: string; amount: number; note?: string }) =>
    apiClient.post('/payments/send/mobile', data),
  sendToBank: (data: { accountNumber: string; ifscCode: string; amount: number; note?: string }) =>
    apiClient.post('/payments/send/bank', data),
  processQR: (data: { qrData: string; amount: number }) => apiClient.post('/payments/qr', data),
  requestMoney: (data: { fromPhone: string; amount: number; note?: string }) =>
    apiClient.post('/payments/request', data),
  getTransactionById: (id: string) => apiClient.get(`/payments/${id}`),
};
