import { useState } from 'react';
import { paymentAPI } from '../services/api/payments';
import toast from 'react-hot-toast';

export const usePayment = () => {
  const [loading, setLoading] = useState(false);

  const sendMoney = async (data: any) => {
    try {
      setLoading(true);
      const response = await paymentAPI.sendToMobile(data);
      toast.success('Payment sent successfully');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Payment failed');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const processQRPayment = async (data: any) => {
    try {
      setLoading(true);
      const response = await paymentAPI.processQR(data);
      toast.success('Payment successful');
      return response.data;
    } catch (err: any) {
      toast.error(err.response?.data?.message || 'Payment failed');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  return {
    loading,
    isLoading: loading,
    sendMoney,
    processQRPayment,
  };
};
