import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { QrCodeIcon, EnvelopeIcon, UserPlusIcon } from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import Input from '../../components/common/Input';
import toast from 'react-hot-toast';

const JoinFamily: React.FC = () => {
  const navigate = useNavigate();
  const [selectedMethod, setSelectedMethod] = useState<'qr' | 'sms' | 'manual' | null>(null);
  const [inviteCode, setInviteCode] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');

  const handleMethodSelect = (method: 'qr' | 'sms' | 'manual') => {
    setSelectedMethod(method);
  };

  const handleQRScan = () => {
    navigate('/scan-family');
  };

  const handleSMSInvite = () => {
    if (!inviteCode) {
      toast.error('Please enter the invite code');
      return;
    }
    // FIXED: Use AcceptInvite with code parameter
    navigate(`/accept-invite?code=${inviteCode}`);
  };

  const handleManualAdd = () => {
    if (!phoneNumber) {
      toast.error('Please enter the primary account holder\'s phone number');
      return;
    }
    // FIXED: For manual entry, we need to go to login with invite flag
    // This simulates that the primary has invited them
    navigate(`/auth?type=linked&invite=manual&phone=${phoneNumber}`);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
      <Card className="max-w-md w-full">
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">Join a Family Account</h1>
          <p className="text-gray-600">Choose how you want to connect</p>
        </div>

        {!selectedMethod ? (
          // Method Selection Screen
          <div className="space-y-4">
            <button
              onClick={() => handleMethodSelect('qr')}
              className="w-full p-6 border-2 border-gray-200 rounded-xl hover:border-primary hover:bg-primary-soft transition-all text-left"
            >
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-primary-soft rounded-full flex items-center justify-center">
                  <QrCodeIcon className="h-6 w-6 text-primary" />
                </div>
                <div>
                  <h3 className="font-semibold text-gray-900">Scan QR Code</h3>
                  <p className="text-sm text-gray-500">Ask primary account holder to show their QR code</p>
                </div>
              </div>
            </button>

            <button
              onClick={() => handleMethodSelect('sms')}
              className="w-full p-6 border-2 border-gray-200 rounded-xl hover:border-primary hover:bg-primary-soft transition-all text-left"
            >
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-primary-soft rounded-full flex items-center justify-center">
                  <EnvelopeIcon className="h-6 w-6 text-primary" />
                </div>
                <div>
                  <h3 className="font-semibold text-gray-900">Enter Invite Code</h3>
                  <p className="text-sm text-gray-500">Use the 6-digit code sent via SMS</p>
                </div>
              </div>
            </button>

            <button
              onClick={() => handleMethodSelect('manual')}
              className="w-full p-6 border-2 border-gray-200 rounded-xl hover:border-primary hover:bg-primary-soft transition-all text-left"
            >
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-primary-soft rounded-full flex items-center justify-center">
                  <UserPlusIcon className="h-6 w-6 text-primary" />
                </div>
                <div>
                  <h3 className="font-semibold text-gray-900">Enter Manually</h3>
                  <p className="text-sm text-gray-500">Enter primary account holder's phone number</p>
                </div>
              </div>
            </button>

            <div className="mt-6 text-center">
              <button
                onClick={() => navigate('/auth?type=linked')}
                className="text-gray-500 hover:text-gray-700 text-sm"
              >
                ← Back to login
              </button>
            </div>
          </div>
        ) : (
          // Method-specific forms
          <div className="space-y-6">
            <button
              onClick={() => setSelectedMethod(null)}
              className="text-gray-500 hover:text-gray-700 text-sm mb-4"
            >
              ← Back to methods
            </button>

            {selectedMethod === 'qr' && (
              <div className="text-center">
                <div className="bg-gray-100 p-8 rounded-lg mb-4">
                  <QrCodeIcon className="h-16 w-16 text-primary mx-auto mb-4" />
                  <p className="text-gray-600 mb-4">
                    Ask the primary account holder to show their QR code in the Family Management section
                  </p>
                </div>
                <Button onClick={handleQRScan} fullWidth>
                  Open QR Scanner
                </Button>
              </div>
            )}

            {selectedMethod === 'sms' && (
              <div className="space-y-4">
                <Input
                  label="Enter Invite Code"
                  placeholder="e.g., FAMILY123"
                  value={inviteCode}
                  onChange={(e) => setInviteCode(e.target.value)}
                />
                <p className="text-sm text-gray-500">
                  The invite code was sent to your mobile number via SMS
                </p>
                <Button onClick={handleSMSInvite} fullWidth disabled={!inviteCode}>
                  Verify Code
                </Button>
              </div>
            )}

            {selectedMethod === 'manual' && (
              <div className="space-y-4">
                <Input
                  label="Primary Account Phone Number"
                  placeholder="9876543210"
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value)}
                />
                <p className="text-sm text-gray-500">
                  Enter the phone number of the primary account holder who invited you
                </p>
                <Button onClick={handleManualAdd} fullWidth disabled={!phoneNumber}>
                  Continue
                </Button>
              </div>
            )}
          </div>
        )}
      </Card>
    </div>
  );
};

export default JoinFamily;