// ErrorPage.tsx
import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
  ExclamationTriangleIcon,
  HomeIcon,
  ArrowPathIcon,
  ArrowLeftIcon,
} from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';

interface ErrorPageProps {
  code?: number;
  title?: string;
  message?: string;
  showHome?: boolean;
  showRetry?: boolean;
  showBack?: boolean;
  onRetry?: () => void;
}

const ErrorPage: React.FC<ErrorPageProps> = ({
  code = 404,
  title,
  message,
  showHome = true,
  showRetry = true,
  showBack = true,
  onRetry,
}) => {
  const navigate = useNavigate();
  const location = useLocation();

  const errorMessages: Record<number, { title: string; message: string }> = {
    400: {
      title: 'Bad Request',
      message: 'The request could not be understood by the server.',
    },
    401: {
      title: 'Unauthorized',
      message: 'Please log in to access this page.',
    },
    403: {
      title: 'Forbidden',
      message: "You don't have permission to access this page.",
    },
    404: {
      title: 'Page Not Found',
      message: "The page you're looking for doesn't exist or has been moved.",
    },
    500: {
      title: 'Server Error',
      message: 'Something went wrong on our end. Please try again later.',
    },
    503: {
      title: 'Service Unavailable',
      message: 'The service is temporarily unavailable. Please try again later.',
    },
  };

  const errorInfo = errorMessages[code] || {
    title: 'Error',
    message: 'An unexpected error occurred.',
  };

  const displayTitle = title || errorInfo.title;
  const displayMessage = message || errorInfo.message;

  const getIcon = () => {
    switch (code) {
      case 401:
      case 403:
        return '🔒';
      case 500:
      case 503:
        return '🔧';
      default:
        return '⚠️';
    }
  };

  return (
    <div className="min-h-[80vh] flex items-center justify-center p-4">
      <Card className="max-w-md w-full text-center">
        {/* Icon */}
        <div className="text-7xl mb-6">{getIcon()}</div>

        {/* Error Code */}
        <div className="inline-block px-4 py-1 bg-primary-soft text-primary rounded-full text-sm font-medium mb-4">
          Error {code}
        </div>

        {/* Title */}
        <h1 className="text-3xl font-bold text-gray-900 mb-3">{displayTitle}</h1>

        {/* Message */}
        <p className="text-gray-600 mb-8">{displayMessage}</p>

        {/* Path Info (for debugging) */}
        {process.env.NODE_ENV === 'development' && location.pathname !== '/404' && (
          <div className="mb-6 p-3 bg-gray-100 rounded-lg text-left">
            <p className="text-xs text-gray-500 mb-1">Attempted path:</p>
            <code className="text-sm">{location.pathname}</code>
          </div>
        )}

        {/* Action Buttons */}
        <div className="space-y-3">
          {showRetry && onRetry && (
            <Button onClick={onRetry} fullWidth>
              <ArrowPathIcon className="h-5 w-5 mr-2" />
              Try Again
            </Button>
          )}

          {showBack && (
            <Button variant="outline" onClick={() => navigate(-1)} fullWidth>
              <ArrowLeftIcon className="h-5 w-5 mr-2" />
              Go Back
            </Button>
          )}

          {showHome && (
            <Button variant="outline" onClick={() => navigate('/')} fullWidth>
              <HomeIcon className="h-5 w-5 mr-2" />
              Go to Home
            </Button>
          )}
        </div>

        {/* Support Link */}
        <p className="mt-6 text-sm text-gray-500">
          Need help?{' '}
          <button onClick={() => navigate('/support')} className="text-primary hover:underline">
            Contact Support
          </button>
        </p>
      </Card>
    </div>
  );
};

export default ErrorPage;
