// SendMoney.tsx
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { PhoneIcon, BuildingLibraryIcon, UserIcon } from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';
import Card from '../../components/common/Card';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { usePayment } from '../../hooks/usePayment';
import { useWallet } from '../../hooks/useWallet';

const sendSchema = z.object({
  type: z.enum(['mobile', 'bank', 'family']),
  recipient: z.string().min(1, 'Recipient required'),
  amount: z.number().min(1, 'Amount must be at least ₹1'),
  note: z.string().optional(),
});

type SendFormData = z.infer<typeof sendSchema>;

const SendMoney: React.FC = () => {
  const navigate = useNavigate();
  const { sendMoney, isLoading } = usePayment();
  const { balance } = useWallet();
  const [selectedType, setSelectedType] = useState<'mobile' | 'bank' | 'family'>('mobile');
  const {
    register,
    handleSubmit,
    setValue,
    formState: { errors },
  } = useForm<SendFormData>({
    resolver: zodResolver(sendSchema),
    defaultValues: { type: 'mobile' },
  });

  const quickAmounts = [100, 200, 500, 1000, 2000];

  const onSubmit = async (data: SendFormData) => {
    try {
      await sendMoney(data);
      toast.success('Money sent successfully!');
      navigate('/primary/transactions');
    } catch (error: any) {
      toast.error(error.message);
    }
  };

  return (
    <div className="max-w-2xl mx-auto">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Send Money</h1>

      <Card>
        {/* Type Selector */}
        <div className="flex gap-3 mb-6">
          {[
            { id: 'mobile', label: 'To Mobile', icon: PhoneIcon },
            { id: 'bank', label: 'To Bank', icon: BuildingLibraryIcon },
            { id: 'family', label: 'Family Member', icon: UserIcon },
          ].map((type) => (
            <button
              key={type.id}
              onClick={() => {
                setSelectedType(type.id as any);
                setValue('type', type.id as any);
              }}
              className={`flex-1 p-3 rounded-lg border-2 transition-colors ${
                selectedType === type.id
                  ? 'border-primary bg-primary-soft'
                  : 'border-gray-200 hover:border-gray-300'
              }`}
            >
              <type.icon
                className={`h-5 w-5 mx-auto mb-1 ${
                  selectedType === type.id ? 'text-primary' : 'text-gray-500'
                }`}
              />
              <span
                className={`text-sm ${
                  selectedType === type.id ? 'text-primary font-medium' : 'text-gray-600'
                }`}
              >
                {type.label}
              </span>
            </button>
          ))}
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          <Input
            label={
              selectedType === 'mobile'
                ? 'Mobile Number'
                : selectedType === 'bank'
                  ? 'Account Number'
                  : 'Select Family Member'
            }
            placeholder={
              selectedType === 'mobile'
                ? '9876543210'
                : selectedType === 'bank'
                  ? 'Enter account number'
                  : 'Choose member'
            }
            {...register('recipient')}
            error={errors.recipient?.message}
          />

          <div>
            <Input
              label="Amount (₹)"
              type="number"
              placeholder="Enter amount"
              {...register('amount', { valueAsNumber: true })}
              error={errors.amount?.message}
            />
            <div className="flex gap-2 mt-2">
              {quickAmounts.map((amt) => (
                <button
                  key={amt}
                  type="button"
                  onClick={() => setValue('amount', amt)}
                  className="px-3 py-1 bg-gray-100 hover:bg-primary-soft text-sm rounded"
                >
                  ₹{amt}
                </button>
              ))}
            </div>
          </div>

          <Input label="Note (Optional)" placeholder="What's this for?" {...register('note')} />

          <div className="bg-gray-50 p-4 rounded-lg">
            <div className="flex justify-between mb-2">
              <span className="text-gray-600">Your Balance</span>
              <span className="font-semibold">₹{balance}</span>
            </div>
            <div className="flex justify-between text-sm text-gray-500">
              <span>Will be deducted</span>
              <span>+ ₹5 convenience fee</span>
            </div>
          </div>

          <Button type="submit" fullWidth size="lg" loading={isLoading}>
            Send Money
          </Button>
        </form>
      </Card>
    </div>
  );
};

export default SendMoney;
