// BankCard.tsx
import React from 'react';
import { BuildingLibraryIcon, CheckCircleIcon } from '@heroicons/react/24/outline';
import Card from '../common/Card';
import Button from '../common/Button';

interface BankCardProps {
  bank: {
    id: string;
    bankName: string;
    accountNumber: string;
    ifscCode: string;
    accountHolder: string;
    balance: number;
    isDefault: boolean;
    isVerified: boolean;
  };
  onSend?: (bankId: string) => void;
  onSetDefault?: (bankId: string) => void;
  onRemove?: (bankId: string) => void;
  onVerify?: (bankId: string) => void;
  showActions?: boolean;
}

const BankCard: React.FC<BankCardProps> = ({
  bank,
  onSend,
  onSetDefault,
  onRemove,
  onVerify,
  showActions = true,
}) => {
  return (
    <Card className="hover:shadow-lg transition-shadow">
      <div className="flex items-start justify-between">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-primary-soft rounded-full flex items-center justify-center">
            <BuildingLibraryIcon className="h-6 w-6 text-primary" />
          </div>
          <div>
            <h3 className="font-semibold text-gray-900">{bank.bankName}</h3>
            <p className="text-sm text-gray-600">{bank.accountNumber}</p>
            <p className="text-xs text-gray-500">IFSC: {bank.ifscCode}</p>
          </div>
        </div>
        {bank.isDefault && (
          <span className="px-2 py-1 bg-green-100 text-green-700 text-xs font-medium rounded-full">
            Default
          </span>
        )}
      </div>

      <div className="mt-4 pt-4 border-t border-gray-100">
        <div className="flex justify-between items-center mb-3">
          <span className="text-sm text-gray-600">Account Holder</span>
          <span className="font-medium">{bank.accountHolder}</span>
        </div>
        <div className="flex justify-between items-center">
          <span className="text-sm text-gray-600">Balance</span>
          <span className="text-lg font-bold text-gray-900">₹{bank.balance.toLocaleString()}</span>
        </div>
      </div>

      {!bank.isVerified && (
        <div className="mt-3 p-2 bg-yellow-50 rounded-lg flex items-center gap-2">
          <span className="text-xs text-yellow-700">Not verified</span>
          {onVerify && (
            <button
              onClick={() => onVerify(bank.id)}
              className="text-xs text-primary hover:underline ml-auto"
            >
              Verify now
            </button>
          )}
        </div>
      )}

      {showActions && (
        <div className="mt-4 flex gap-2">
          {onSend && (
            <Button variant="primary" size="sm" onClick={() => onSend(bank.id)} className="flex-1">
              Send
            </Button>
          )}
          {!bank.isDefault && onSetDefault && (
            <Button
              variant="outline"
              size="sm"
              onClick={() => onSetDefault(bank.id)}
              className="flex-1"
            >
              Set Default
            </Button>
          )}
          {onRemove && (
            <Button
              variant="outline"
              size="sm"
              onClick={() => onRemove(bank.id)}
              className="flex-1 text-error border-error hover:bg-error-soft"
            >
              Remove
            </Button>
          )}
        </div>
      )}
    </Card>
  );
};

export default BankCard;
