// banks.ts
import apiClient from './client';

export const bankAPI = {
  getBanks: () => apiClient.get('/banks'),
  getBankById: (id: string) => apiClient.get(`/banks/${id}`),
  addBank: (data: any) => apiClient.post('/banks', data),
  updateBank: (id: string, data: any) => apiClient.put(`/banks/${id}`, data),
  deleteBank: (id: string) => apiClient.delete(`/banks/${id}`),
  verifyBank: (id: string) => apiClient.post(`/banks/${id}/verify`),
  getBankTransactions: (id: string, params?: any) =>
    apiClient.get(`/banks/${id}/transactions`, { params }),
};
