// AddFamilyMember.tsx
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { QRCodeSVG } from 'qrcode.react';
import {
  QrCodeIcon,
  EnvelopeIcon,
  UserPlusIcon,
  DocumentDuplicateIcon,
} from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';
import Card from '../../components/common/Card';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import LimitSetter from '../../components/family/LimitSetter';
import { useFamily } from '../../hooks/useFamily';

type AddMethod = 'qr' | 'sms' | 'manual';

const AddFamilyMember: React.FC = () => {
  const navigate = useNavigate();
  const { inviteMember, generateQR } = useFamily();
  const [method, setMethod] = useState<AddMethod>('qr');
  const [step, setStep] = useState(1);
  const [qrData, setQrData] = useState<any>(null);
  const [formData, setFormData] = useState({
    phone: '',
    name: '',
    relationship: '',
  });

  const handleGenerateQR = async () => {
    const data = await generateQR();
    setQrData(data);
    setStep(2);
  };

  const handleSendInvite = async () => {
    try {
      await inviteMember({ ...formData, ...limits });
      toast.success('Invitation sent!');
      navigate('/primary/family');
    } catch (error: any) {
      toast.error(error.message);
    }
  };

  const [limits, setLimits] = useState({
    dailyLimit: 500,
    monthlyLimit: 5000,
    perTransactionLimit: 200,
    sendMoney: true,
    scanPay: true,
    recharge: true,
    viewHistory: true,
  });

  const methods = [
    { id: 'qr', label: 'QR Code', icon: QrCodeIcon, desc: 'They scan your screen' },
    { id: 'sms', label: 'SMS Invite', icon: EnvelopeIcon, desc: 'Send invite via text' },
    { id: 'manual', label: 'Add Manually', icon: UserPlusIcon, desc: 'Enter details now' },
  ];

  if (step === 2 && method === 'qr') {
    return (
      <div className="max-w-md mx-auto">
        <Card>
          <h2 className="text-2xl font-bold text-center mb-6">Scan QR Code</h2>

          <div className="bg-white p-6 rounded-lg border-2 border-dashed flex flex-col items-center mb-6">
            <QRCodeSVG value={JSON.stringify(qrData)} size={200} />
          </div>

          <div className="space-y-4">
            <p className="text-center text-gray-600">Ask family member to scan this QR code</p>
            <p className="text-sm text-gray-500 text-center">Code expires in 10 minutes</p>

            <Button
              variant="outline"
              fullWidth
              onClick={() => navigator.clipboard.writeText(JSON.stringify(qrData))}
            >
              <DocumentDuplicateIcon className="h-4 w-4 mr-1" /> Copy Link
            </Button>

            <Button fullWidth onClick={() => navigate('/primary/family')}>
              Done
            </Button>
          </div>
        </Card>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Add Family Member</h1>

      {step === 1 ? (
        <>
          {/* Method Selection */}
          <div className="grid md:grid-cols-3 gap-4 mb-6">
            {methods.map((m) => (
              <button
                key={m.id}
                onClick={() => setMethod(m.id as AddMethod)}
                className={`p-4 rounded-xl border-2 transition-all ${
                  method === m.id
                    ? 'border-primary bg-primary-soft'
                    : 'border-gray-200 hover:border-gray-300'
                }`}
              >
                <m.icon
                  className={`h-8 w-8 mx-auto mb-2 ${
                    method === m.id ? 'text-primary' : 'text-gray-500'
                  }`}
                />
                <h3
                  className={`font-semibold ${method === m.id ? 'text-primary' : 'text-gray-700'}`}
                >
                  {m.label}
                </h3>
                <p className="text-xs text-gray-500 mt-1">{m.desc}</p>
              </button>
            ))}
          </div>

          {/* Form */}
          {(method === 'sms' || method === 'manual') && (
            <Card>
              <h2 className="text-lg font-semibold mb-4">
                {method === 'sms' ? 'Send SMS Invite' : 'Enter Member Details'}
              </h2>

              <div className="space-y-4">
                <Input
                  label="Mobile Number"
                  placeholder="Enter 10-digit number"
                  value={formData.phone}
                  onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                />

                {method === 'manual' && (
                  <>
                    <Input
                      label="Full Name"
                      placeholder="Enter name"
                      value={formData.name}
                      onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    />
                    <Input
                      label="Relationship"
                      placeholder="e.g., Daughter, Son, Mother"
                      value={formData.relationship}
                      onChange={(e) => setFormData({ ...formData, relationship: e.target.value })}
                    />
                  </>
                )}

                <Button fullWidth onClick={() => setStep(2)} disabled={!formData.phone}>
                  Next: Set Limits
                </Button>
              </div>
            </Card>
          )}

          {method === 'qr' && (
            <Card>
              <p className="text-center mb-4">Generate a QR code for your family member to scan</p>
              <Button fullWidth onClick={handleGenerateQR}>
                Generate QR Code
              </Button>
            </Card>
          )}
        </>
      ) : (
        <>
          <LimitSetter
            memberName={formData.name || 'New Member'}
            initialValues={limits}
            onSubmit={async (data) => {
              setLimits(data);
              if (method === 'qr') {
                navigate('/primary/family');
              } else {
                await handleSendInvite();
              }
            }}
            onCancel={() => setStep(1)}
          />
        </>
      )}
    </div>
  );
};

export default AddFamilyMember;
