import React from 'react';
import { NavLink } from 'react-router-dom';
import {
  HomeIcon,
  PaperAirplaneIcon,
  QrCodeIcon,
  ClockIcon,
  UserIcon,
} from '@heroicons/react/24/outline';
import {
  HomeIcon as HomeIconSolid,
  PaperAirplaneIcon as PaperAirplaneIconSolid,
  QrCodeIcon as QrCodeIconSolid,
  ClockIcon as ClockIconSolid,
  UserIcon as UserIconSolid,
} from '@heroicons/react/24/solid';
import { useAuth } from '../../hooks/useAuth';

interface MobileNavProps {
  className?: string;
}

const MobileNav: React.FC<MobileNavProps> = ({ className = '' }) => {
  const { user, isAuthenticated } = useAuth();

  if (!isAuthenticated) return null;

  // Navigation items based on user role
  const getNavItems = () => {
    if (user?.role === 'PRIMARY') {
      return [
        { name: 'Home', href: '/primary/dashboard', icon: HomeIcon, activeIcon: HomeIconSolid },
        {
          name: 'Send',
          href: '/primary/send',
          icon: PaperAirplaneIcon,
          activeIcon: PaperAirplaneIconSolid,
        },
        { name: 'Scan', href: '/primary/scan', icon: QrCodeIcon, activeIcon: QrCodeIconSolid },
        {
          name: 'History',
          href: '/primary/transactions',
          icon: ClockIcon,
          activeIcon: ClockIconSolid,
        },
        { name: 'Profile', href: '/profile', icon: UserIcon, activeIcon: UserIconSolid },
      ];
    } else {
      return [
        { name: 'Home', href: '/linked/dashboard', icon: HomeIcon, activeIcon: HomeIconSolid },
        {
          name: 'Send',
          href: '/linked/send',
          icon: PaperAirplaneIcon,
          activeIcon: PaperAirplaneIconSolid,
        },
        { name: 'Scan', href: '/linked/scan', icon: QrCodeIcon, activeIcon: QrCodeIconSolid },
        { name: 'History', href: '/linked/history', icon: ClockIcon, activeIcon: ClockIconSolid },
        { name: 'Profile', href: '/profile', icon: UserIcon, activeIcon: UserIconSolid },
      ];
    }
  };

  const navItems = getNavItems();

  return (
    <nav
      className={`lg:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 z-40 ${className}`}
    >
      <div className="flex items-center justify-around h-16">
        {navItems.map((item) => (
          <NavLink
            key={item.name}
            to={item.href}
            className={({ isActive }) =>
              `flex flex-col items-center justify-center flex-1 h-full transition-colors
              ${isActive ? 'text-primary' : 'text-gray-400 hover:text-gray-600'}`
            }
          >
            {({ isActive }) => (
              <>
                {isActive ? (
                  <item.activeIcon className="h-6 w-6" />
                ) : (
                  <item.icon className="h-6 w-6" />
                )}
                <span className="text-xs mt-1">{item.name}</span>
              </>
            )}
          </NavLink>
        ))}
      </div>
    </nav>
  );
};

export default MobileNav;
