// auth.ts
import apiClient from './client';

export const authAPI = {
  sendOTP: (data: { phone: string }) => apiClient.post('/auth/send-otp', data),
  verifyOTP: (data: { phone: string; otp: string; userType?: 'primary' | 'linked' }) =>
    apiClient.post('/auth/verify-otp', data),
  getMe: () => apiClient.get('/auth/me'),
  updateProfile: (data: { name?: string; email?: string }) => apiClient.put('/auth/profile', data),
  changePin: (data: { oldPin: string; newPin: string }) => apiClient.put('/auth/change-pin', data),
  logout: () => apiClient.post('/auth/logout'),
};
