// LinkedProfile.tsx
import React from 'react';
import { useNavigate } from 'react-router-dom';
import {
  UserIcon,
  PhoneIcon,
  EnvelopeIcon,
  ArrowTrendingUpIcon,
  ClockIcon,
  ArrowRightOnRectangleIcon,
} from '@heroicons/react/24/outline';
import Card from '../../components/common/Card';
import Button from '../../components/common/Button';
import ProgressBar from '../../components/common/ProgressBar';
import { useAuth } from '../../hooks/useAuth';
import { useFamily } from '../../hooks/useFamily';

const LinkedProfile: React.FC = () => {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const { limits } = useFamily();

  const dailyPercent = ((limits?.dailySpent || 0) / (limits?.dailyLimit || 1)) * 100;
  const monthlyPercent = ((limits?.monthlySpent || 0) / (limits?.monthlyLimit || 1)) * 100;

  const handleLogout = async () => {
    if (confirm('Are you sure you want to logout?')) {
      await logout();
      navigate('/');
    }
  };

  return (
    <div className="max-w-2xl mx-auto">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">My Profile</h1>

      {/* Profile Card */}
      <Card className="mb-6">
        <div className="flex items-center gap-4">
          <div className="w-20 h-20 bg-primary-soft rounded-full flex items-center justify-center">
            <UserIcon className="h-10 w-10 text-primary" />
          </div>
          <div className="flex-1">
            <h2 className="text-xl font-bold">{user?.name || 'User'}</h2>
            <p className="text-gray-600 flex items-center gap-1 mt-1">
              <PhoneIcon className="h-4 w-4" /> {user?.phone}
            </p>
            {user?.email && (
              <p className="text-gray-600 flex items-center gap-1 mt-1">
                <EnvelopeIcon className="h-4 w-4" /> {user?.email}
              </p>
            )}
          </div>
          <Button variant="outline" size="sm" onClick={() => navigate('/linked/profile/edit')}>
            Edit
          </Button>
        </div>
      </Card>

      {/* Account Type */}
      <Card className="mb-6 bg-primary-soft">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-sm text-gray-600">Account Type</p>
            <p className="text-lg font-bold text-primary">Linked Account</p>
          </div>
          <span className="px-3 py-1 bg-primary text-white text-sm rounded-full">Active</span>
        </div>
      </Card>

      {/* Limits Summary */}
      <Card className="mb-6">
        <h3 className="font-semibold mb-4">My Spending Limits</h3>

        <div className="mb-4">
          <div className="flex justify-between text-sm mb-1">
            <span className="text-gray-600">Daily Limit</span>
            <span className="font-medium">
              ₹{limits?.dailySpent} / ₹{limits?.dailyLimit}
            </span>
          </div>
          <ProgressBar value={dailyPercent} color={dailyPercent > 80 ? 'warning' : 'primary'} />
        </div>

        <div className="mb-4">
          <div className="flex justify-between text-sm mb-1">
            <span className="text-gray-600">Monthly Limit</span>
            <span className="font-medium">
              ₹{limits?.monthlySpent} / ₹{limits?.monthlyLimit}
            </span>
          </div>
          <ProgressBar value={monthlyPercent} color={monthlyPercent > 80 ? 'warning' : 'primary'} />
        </div>

        <div className="bg-gray-50 p-3 rounded-lg">
          <p className="text-sm text-gray-600">
            Per Transaction Limit:{' '}
            <span className="font-semibold">₹{limits?.perTransactionLimit}</span>
          </p>
        </div>
      </Card>

      {/* Quick Actions */}
      <Card className="mb-6">
        <h3 className="font-semibold mb-3">Quick Actions</h3>
        <div className="space-y-2">
          <button
            onClick={() => navigate('/linked/request-increase')}
            className="w-full p-3 text-left hover:bg-gray-50 rounded-lg flex items-center gap-3"
          >
            <ArrowTrendingUpIcon className="h-5 w-5 text-primary" />
            <span>Request Limit Increase</span>
          </button>
          <button
            onClick={() => navigate('/linked/history')}
            className="w-full p-3 text-left hover:bg-gray-50 rounded-lg flex items-center gap-3"
          >
            <ClockIcon className="h-5 w-5 text-primary" />
            <span>View Transaction History</span>
          </button>
        </div>
      </Card>

      {/* Linked To */}
      <Card className="mb-6 bg-gray-50">
        <p className="text-sm text-gray-600 mb-1">Linked to Primary Account</p>
        <p className="font-semibold">{limits?.primaryName || 'Primary Account'}</p>
      </Card>

      {/* Logout Button */}
      <Button
        variant="outline"
        fullWidth
        size="lg"
        onClick={handleLogout}
        className="border-error text-error hover:bg-error-soft"
      >
        <ArrowRightOnRectangleIcon className="h-5 w-5 mr-2" />
        Logout
      </Button>
    </div>
  );
};

export default LinkedProfile;
