import React from 'react';
import { Link } from 'react-router-dom';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  href?: string;
  fullWidth?: boolean;
  loading?: boolean;
  children: React.ReactNode;
}

const Button: React.FC<ButtonProps> = ({
  variant = 'primary',
  size = 'md',
  href,
  fullWidth = false,
  loading = false,
  children,
  className = '',
  disabled,
  ...props
}) => {
  // Base styles
  const baseStyles =
    'font-semibold rounded-button transition-all duration-200 inline-flex items-center justify-center focus:outline-none focus:ring-2 focus:ring-offset-2';

  // Variant styles
  const variants = {
    primary:
      'bg-primary text-white hover:bg-primary-dark focus:ring-primary-light disabled:bg-primary-light',
    secondary:
      'bg-white text-primary border-2 border-primary hover:bg-primary-soft focus:ring-primary-light',
    outline:
      'bg-transparent text-gray-700 border-2 border-gray-300 hover:border-primary hover:text-primary focus:ring-gray-400',
    danger: 'bg-error text-white hover:bg-red-700 focus:ring-red-400',
  };

  // Size styles
  const sizes = {
    sm: 'px-4 py-2 text-sm',
    md: 'px-6 py-3 text-base',
    lg: 'px-8 py-4 text-lg',
  };

  // Width style
  const width = fullWidth ? 'w-full' : '';

  // Disabled style
  const isDisabled = disabled || loading;
  const disabledStyles = isDisabled ? 'opacity-50 cursor-not-allowed pointer-events-none' : '';

  const classes = `${baseStyles} ${variants[variant]} ${sizes[size]} ${width} ${disabledStyles} ${className}`;

  // Loading spinner
  const spinner = (
    <svg
      className="animate-spin -ml-1 mr-3 h-5 w-5"
      xmlns="http://www.w3.org/2000/svg"
      fill="none"
      viewBox="0 0 24 24"
    >
      <circle
        className="opacity-25"
        cx="12"
        cy="12"
        r="10"
        stroke="currentColor"
        strokeWidth="4"
      ></circle>
      <path
        className="opacity-75"
        fill="currentColor"
        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
      ></path>
    </svg>
  );

  // If href is provided, render as Link
  if (href) {
    return (
      <Link to={href} className={classes}>
        {loading && spinner}
        {children}
      </Link>
    );
  }

  // Otherwise render as button
  return (
    <button className={classes} disabled={isDisabled} {...props}>
      {loading && spinner}
      {children}
    </button>
  );
};

export default Button;
